248	
249		/**
250		 * Create a new {@link SpringApplication} instance. The application context will load
251		 * beans from the specified primary sources (see {@link SpringApplication class-level}
252		 * documentation for details). The instance can be customized before calling
253		 * {@link #run(String...)}.
254		 * @param primarySources the primary bean sources
255		 * @see #run(Class, String[])
256		 * @see #SpringApplication(ResourceLoader, Class...)
257		 * @see #setSources(Set)
258		 */
259		public SpringApplication(Class<?>... primarySources) {
260			this(null, primarySources);
261		}
262	
263		/**
264		 * Create a new {@link SpringApplication} instance. The application context will load
265		 * beans from the specified primary sources (see {@link SpringApplication class-level}
266		 * documentation for details). The instance can be customized before calling
267		 * {@link #run(String...)}.
268		 * @param resourceLoader the resource loader to use
269		 * @param primarySources the primary bean sources
270		 * @see #run(Class, String[])
271		 * @see #setSources(Set)
272		 */
273		@SuppressWarnings({ "unchecked", "rawtypes" })
274		public SpringApplication(@Nullable ResourceLoader resourceLoader, Class<?>... primarySources) {
275			this.resourceLoader = resourceLoader;
276			Assert.notNull(primarySources, "'primarySources' must not be null");
277			this.primarySources = new LinkedHashSet<>(Arrays.asList(primarySources));
278			this.properties.setWebApplicationType(WebApplicationType.deduce());
279			this.bootstrapRegistryInitializers = new ArrayList<>(
280					getSpringFactoriesInstances(BootstrapRegistryInitializer.class));
281			setInitializers((Collection) getSpringFactoriesInstances(ApplicationContextInitializer.class));
282			setListeners((Collection) getSpringFactoriesInstances(ApplicationListener.class));
283			this.mainApplicationClass = deduceMainApplicationClass();
284		}
285	
286		private @Nullable Class<?> deduceMainApplicationClass() {
287			return StackWalker.getInstance(StackWalker.Option.RETAIN_CLASS_REFERENCE)
288				.walk(this::findMainClass)
289				.orElse(null);
290		}
291	
292		private Optional<Class<?>> findMainClass(Stream<StackFrame> stack) {
293			return stack.filter((frame) -> Objects.equals(frame.getMethodName(), "main"))
294				.findFirst()
295				.map(StackWalker.StackFrame::getDeclaringClass);
296		}
297	
298		/**
299		 * Run the Spring application, creating and refreshing a new
300		 * {@link ApplicationContext}.
301		 * @param args the application arguments (usually passed from a Java main method)
302		 * @return a running {@link ApplicationContext}
303		 */
304		public ConfigurableApplicationContext run(String... args) {
305			Startup startup = Startup.create();
306			if (this.properties.isRegisterShutdownHook()) {
307				SpringApplication.shutdownHook.enableShutdownHookAddition();
308			}
309			DefaultBootstrapContext bootstrapContext = createBootstrapContext();
310			ConfigurableApplicationContext context = null;
311			configureHeadlessProperty();
312			SpringApplicationRunListeners listeners = getRunListeners(args);
313			listeners.starting(bootstrapContext, this.mainApplicationClass);
314			try {
315				ApplicationArguments applicationArguments = new DefaultApplicationArguments(args);
316				ConfigurableEnvironment environment = prepareEnvironment(listeners, bootstrapContext, applicationArguments);
317				Banner printedBanner = printBanner(environment);
318				context = createApplicationContext();
319				context.setApplicationStartup(this.applicationStartup);
320				prepareContext(bootstrapContext, context, environment, listeners, applicationArguments, printedBanner);
321				refreshContext(context);
322				afterRefresh(context, applicationArguments);
323				Duration timeTakenToStarted = startup.started();
324				if (this.properties.isLogStartupInfo()) {
325					new StartupInfoLogger(this.mainApplicationClass, environment).logStarted(getApplicationLog(), startup);
326				}
327				listeners.started(context, timeTakenToStarted);
328				callRunners(context, applicationArguments);
329			}
330			catch (Throwable ex) {
331				throw handleRunFailure(context, ex, listeners);
332			}
333			try {
334				if (context.isRunning()) {
335					listeners.ready(context, startup.ready());
336				}
337			}
338			catch (Throwable ex) {
339				throw handleRunFailure(context, ex, null);
340			}
341			return context;
342		}
343	
344		private DefaultBootstrapContext createBootstrapContext() {
345			DefaultBootstrapContext bootstrapContext = new DefaultBootstrapContext();
346			this.bootstrapRegistryInitializers.forEach((initializer) -> initializer.initialize(bootstrapContext));
347			return bootstrapContext;
348		}
349	
350		private ConfigurableEnvironment prepareEnvironment(SpringApplicationRunListeners listeners,
351				DefaultBootstrapContext bootstrapContext, ApplicationArguments applicationArguments) {
352			// Create and configure the environment
353			ConfigurableEnvironment environment = getOrCreateEnvironment();
354			configureEnvironment(environment, applicationArguments.getSourceArgs());
355			ConfigurationPropertySources.attach(environment);
356			listeners.environmentPrepared(bootstrapContext, environment);
357			ApplicationInfoPropertySource.moveToEnd(environment);
358			DefaultPropertiesPropertySource.moveToEnd(environment);
359			Assert.state(!environment.containsProperty("spring.main.environment-prefix"),
360					"Environment prefix cannot be set via properties.");
361			bindToSpringApplication(environment);
362			if (!this.isCustomEnvironment) {
363				EnvironmentConverter environmentConverter = new EnvironmentConverter(getClassLoader());
364				environment = environmentConverter.convertEnvironmentIfNecessary(environment, deduceEnvironmentClass());
365			}
366			ConfigurationPropertySources.attach(environment);
367			return environment;
368		}
369	
370		private Class<? extends ConfigurableEnvironment> deduceEnvironmentClass() {
371			WebApplicationType webApplicationType = this.properties.getWebApplicationType();
372			Class<? extends ConfigurableEnvironment> environmentType = this.applicationContextFactory
373				.getEnvironmentType(webApplicationType);
374			if (environmentType == null && this.applicationContextFactory != ApplicationContextFactory.DEFAULT) {
375				environmentType = ApplicationContextFactory.DEFAULT.getEnvironmentType(webApplicationType);
376			}
377			return (environmentType != null) ? environmentType : ApplicationEnvironment.class;
378		}
379	
380		private void prepareContext(DefaultBootstrapContext bootstrapContext, ConfigurableApplicationContext context,
381				ConfigurableEnvironment environment, SpringApplicationRunListeners listeners,
382				ApplicationArguments applicationArguments, @Nullable Banner printedBanner) {
383			context.setEnvironment(environment);
384			postProcessApplicationContext(context);
385			addAotGeneratedInitializerIfNecessary(this.initializers);
386			ConfigurableListableBeanFactory beanFactory = context.getBeanFactory();
387			if (beanFactory instanceof AbstractAutowireCapableBeanFactory autowireCapableBeanFactory) {
388				autowireCapableBeanFactory.setAllowCircularReferences(this.properties.isAllowCircularReferences());
389				if (beanFactory instanceof DefaultListableBeanFactory listableBeanFactory) {
390					listableBeanFactory.setAllowBeanDefinitionOverriding(this.properties.isAllowBeanDefinitionOverriding());
391				}
392			}
393			applyInitializers(context);
394			listeners.contextPrepared(context);
395			bootstrapContext.close(context);
396			if (this.properties.isLogStartupInfo()) {
397				logStartupInfo(context);
398				logStartupProfileInfo(context);
399			}
400			// Add boot specific singleton beans
401			beanFactory.registerSingleton("springApplicationArguments", applicationArguments);
402			if (printedBanner != null) {
403				beanFactory.registerSingleton("springBootBanner", printedBanner);
404			}
405			if (this.properties.isLazyInitialization()) {
406				context.addBeanFactoryPostProcessor(new LazyInitializationBeanFactoryPostProcessor());
407			}
408			if (this.properties.isKeepAlive()) {
409				context.addApplicationListener(new KeepAlive());
410			}
411			context.addBeanFactoryPostProcessor(new PropertySourceOrderingBeanFactoryPostProcessor(context));
412			if (!AotDetector.useGeneratedArtifacts()) {
413				// Load the sources
414				Set<Object> sources = getAllSources();
415				Assert.state(!ObjectUtils.isEmpty(sources), "No sources defined");
416				load(context, sources.toArray(new Object[0]));
417			}
418			listeners.contextLoaded(context);
419		}
420	
421		private void addAotGeneratedInitializerIfNecessary(List<ApplicationContextInitializer<?>> initializers) {
422			if (AotDetector.useGeneratedArtifacts()) {
423				List<ApplicationContextInitializer<?>> aotInitializers = new ArrayList<>(
424						initializers.stream().filter(AotApplicationContextInitializer.class::isInstance).toList());
425				if (aotInitializers.isEmpty()) {
426					Assert.state(this.mainApplicationClass != null, "No application main class found");
427					String initializerClassName = this.mainApplicationClass.getName() + "__ApplicationContextInitializer";
428					if (!ClassUtils.isPresent(initializerClassName, getClassLoader())) {
429						throw new AotInitializerNotFoundException(this.mainApplicationClass, initializerClassName);
430					}
431					aotInitializers.add(AotApplicationContextInitializer.forInitializerClasses(initializerClassName));
432				}
433				initializers.removeAll(aotInitializers);
434				initializers.addAll(0, aotInitializers);
435			}
436			if (NativeDetector.inNativeImage()) {
437				NativeImageRequirementsException.throwIfNotMet();
438			}
439		}
440	
441		private void refreshContext(ConfigurableApplicationContext context) {
442			if (this.properties.isRegisterShutdownHook()) {
443				shutdownHook.registerApplicationContext(context);
444			}
445			refresh(context);
446		}
447	
448		private void configureHeadlessProperty() {
449			System.setProperty(SYSTEM_PROPERTY_JAVA_AWT_HEADLESS,
450					System.getProperty(SYSTEM_PROPERTY_JAVA_AWT_HEADLESS, Boolean.toString(this.headless)));
451		}
452	
453		private SpringApplicationRunListeners getRunListeners(String[] args) {
454			ArgumentResolver argumentResolver = ArgumentResolver.of(SpringApplication.class, this);
455			argumentResolver = argumentResolver.and(String[].class, args);
456			List<SpringApplicationRunListener> listeners = getSpringFactoriesInstances(SpringApplicationRunListener.class,
457					argumentResolver);
458			SpringApplicationHook hook = applicationHook.get();
459			SpringApplicationRunListener hookListener = (hook != null) ? hook.getRunListener(this) : null;
460			if (hookListener != null) {
461				listeners = new ArrayList<>(listeners);
462				listeners.add(hookListener);
463			}
464			return new SpringApplicationRunListeners(logger, listeners, this.applicationStartup);
465		}
466	
467		private <T> List<T> getSpringFactoriesInstances(Class<T> type) {
468			return getSpringFactoriesInstances(type, null);
469		}
470	
471		private <T> List<T> getSpringFactoriesInstances(Class<T> type, @Nullable ArgumentResolver argumentResolver) {
472			return SpringFactoriesLoader.forDefaultResourceLocation(getClassLoader()).load(type, argumentResolver);
473		}
474	
475		private ConfigurableEnvironment getOrCreateEnvironment() {
476			if (this.environment != null) {
477				return this.environment;
