767		private void callRunners(ConfigurableApplicationContext context, ApplicationArguments args) {
768			ConfigurableListableBeanFactory beanFactory = context.getBeanFactory();
769			String[] beanNames = beanFactory.getBeanNamesForType(Runner.class);
770			Map<Runner, String> instancesToBeanNames = new IdentityHashMap<>();
771			for (String beanName : beanNames) {
772				instancesToBeanNames.put(beanFactory.getBean(beanName, Runner.class), beanName);
773			}
774			Comparator<Object> comparator = getOrderComparator(beanFactory)
775				.withSourceProvider(new FactoryAwareOrderSourceProvider(beanFactory, instancesToBeanNames));
776			instancesToBeanNames.keySet().stream().sorted(comparator).forEach((runner) -> callRunner(runner, args));
777		}
778	
779		private OrderComparator getOrderComparator(ConfigurableListableBeanFactory beanFactory) {
780			Comparator<?> dependencyComparator = (beanFactory instanceof DefaultListableBeanFactory defaultListableBeanFactory)
781					? defaultListableBeanFactory.getDependencyComparator() : null;
782			return (dependencyComparator instanceof OrderComparator orderComparator) ? orderComparator
783					: AnnotationAwareOrderComparator.INSTANCE;
784		}
785	
786		private void callRunner(Runner runner, ApplicationArguments args) {
787			if (runner instanceof ApplicationRunner) {
788				callRunner(ApplicationRunner.class, runner, (applicationRunner) -> applicationRunner.run(args));
789			}
790			if (runner instanceof CommandLineRunner) {
791				callRunner(CommandLineRunner.class, runner,
792						(commandLineRunner) -> commandLineRunner.run(args.getSourceArgs()));
793			}
794		}
