894		private int getExitCodeFromException(@Nullable ConfigurableApplicationContext context, Throwable exception) {
895			int exitCode = getExitCodeFromMappedException(context, exception);
896			if (exitCode == 0) {
897				exitCode = getExitCodeFromExitCodeGeneratorException(exception);
898			}
899			return exitCode;
900		}
901	
902		private int getExitCodeFromMappedException(@Nullable ConfigurableApplicationContext context, Throwable exception) {
903			if (context == null || !context.isActive()) {
904				return 0;
905			}
906			ExitCodeGenerators generators = new ExitCodeGenerators();
907			Collection<ExitCodeExceptionMapper> beans = context.getBeansOfType(ExitCodeExceptionMapper.class).values();
908			generators.addAll(exception, beans);
909			return generators.getExitCode();
910		}
911	
912		private int getExitCodeFromExitCodeGeneratorException(@Nullable Throwable exception) {
913			if (exception == null) {
914				return 0;
915			}
916			if (exception instanceof ExitCodeGenerator generator) {
917				return generator.getExitCode();
918			}
919			return getExitCodeFromExitCodeGeneratorException(exception.getCause());
920		}
