1695		/**
1696		 * Starts a non-daemon thread to keep the JVM alive on {@link ContextRefreshedEvent}.
1697		 * Stops the thread on {@link ContextClosedEvent}.
1698		 */
1699		private static final class KeepAlive implements ApplicationListener<ApplicationContextEvent> {
1700	
1701			private final AtomicReference<@Nullable Thread> thread = new AtomicReference<>();
1702	
1703			@Override
1704			public void onApplicationEvent(ApplicationContextEvent event) {
1705				if (event instanceof ContextRefreshedEvent) {
1706					startKeepAliveThread();
1707				}
1708				else if (event instanceof ContextClosedEvent) {
1709					stopKeepAliveThread();
1710				}
1711			}
1712	
1713			private void startKeepAliveThread() {
1714				Thread thread = new Thread(() -> {
1715					while (true) {
1716						try {
1717							Thread.sleep(Long.MAX_VALUE);
1718						}
1719						catch (InterruptedException ex) {
1720							break;
1721						}
1722					}
1723				});
1724				if (this.thread.compareAndSet(null, thread)) {
1725					thread.setDaemon(false);
1726					thread.setName("keep-alive");
1727					thread.start();
1728				}
1729			}
1730	
1731			private void stopKeepAliveThread() {
1732				Thread thread = this.thread.getAndSet(null);
1733				if (thread == null) {
1734					return;
1735				}
1736				thread.interrupt();
