1742		 * Strategy used to handle startup concerns.
1743		 */
1744		abstract static class Startup {
1745	
1746			private @Nullable Duration timeTakenToStarted;
1747	
1748			protected abstract long startTime();
1749	
1750			protected abstract @Nullable Long processUptime();
1751	
1752			protected abstract String action();
1753	
1754			final Duration started() {
1755				long now = System.currentTimeMillis();
1756				this.timeTakenToStarted = Duration.ofMillis(now - startTime());
1757				return this.timeTakenToStarted;
1758			}
1759	
1760			Duration timeTakenToStarted() {
1761				Assert.state(this.timeTakenToStarted != null,
1762						"timeTakenToStarted is not set. Make sure to call started() before this method");
1763				return this.timeTakenToStarted;
1764			}
1765	
1766			private Duration ready() {
1767				long now = System.currentTimeMillis();
1768				return Duration.ofMillis(now - startTime());
1769			}
1770	
1771			static Startup create() {
1772				ClassLoader classLoader = Startup.class.getClassLoader();
1773				return (ClassUtils.isPresent("jdk.crac.management.CRaCMXBean", classLoader)
1774						&& ClassUtils.isPresent("org.crac.management.CRaCMXBean", classLoader))
1775								? new CoordinatedRestoreAtCheckpointStartup() : new StandardStartup();
1776			}
1777	
1778		}
