1781		 * Standard {@link Startup} implementation.
1782		 */
1783		private static final class StandardStartup extends Startup {
1784	
1785			private final Long startTime = System.currentTimeMillis();
1786	
1787			@Override
1788			protected long startTime() {
1789				return this.startTime;
1790			}
1791	
1792			@Override
1793			protected @Nullable Long processUptime() {
1794				try {
1795					return ManagementFactory.getRuntimeMXBean().getUptime();
1796				}
1797				catch (Throwable ex) {
1798					return null;
1799				}
1800			}
1801	
1802			@Override
1803			protected String action() {
1804				return "Started";
1805			}
1806	
1807		}
