1809		/**
1810		 * Coordinated-Restore-At-Checkpoint {@link Startup} implementation.
1811		 */
1812		private static final class CoordinatedRestoreAtCheckpointStartup extends Startup {
1813	
1814			private final StandardStartup fallback = new StandardStartup();
1815	
1816			@Override
1817			protected @Nullable Long processUptime() {
1818				Long uptime = CRaCMXBean.getCRaCMXBean().getUptimeSinceRestore();
1819				return (uptime >= 0) ? uptime : this.fallback.processUptime();
1820			}
1821	
1822			@Override
1823			protected String action() {
1824				return (restoreTime() >= 0) ? "Restored" : this.fallback.action();
1825			}
1826	
1827			private long restoreTime() {
1828				return CRaCMXBean.getCRaCMXBean().getRestoreTime();
1829			}
1830	
1831			@Override
1832			protected long startTime() {
1833				long restoreTime = restoreTime();
1834				return (restoreTime >= 0) ? restoreTime : this.fallback.startTime();
1835			}
1836	
1837		}
