1839		/**
1840		 * {@link OrderSourceProvider} used to obtain factory method and target type order
1841		 * sources. Based on internal {@link DefaultListableBeanFactory} code.
1842		 */
1843		private static class FactoryAwareOrderSourceProvider implements OrderSourceProvider {
1844	
1845			private final ConfigurableBeanFactory beanFactory;
1846	
1847			private final Map<?, String> instancesToBeanNames;
1848	
1849			FactoryAwareOrderSourceProvider(ConfigurableBeanFactory beanFactory, Map<?, String> instancesToBeanNames) {
1850				this.beanFactory = beanFactory;
1851				this.instancesToBeanNames = instancesToBeanNames;
1852			}
1853	
1854			@Override
1855			public @Nullable Object getOrderSource(Object obj) {
1856				String beanName = this.instancesToBeanNames.get(obj);
1857				return (beanName != null) ? getOrderSource(beanName, obj.getClass()) : null;
1858			}
1859	
1860			private @Nullable Object getOrderSource(String beanName, Class<?> instanceType) {
1861				try {
1862					RootBeanDefinition beanDefinition = (RootBeanDefinition) this.beanFactory
1863						.getMergedBeanDefinition(beanName);
1864					Method factoryMethod = beanDefinition.getResolvedFactoryMethod();
1865					Class<?> targetType = beanDefinition.getTargetType();
1866					targetType = (targetType != instanceType) ? targetType : null;
1867					return Stream.of(factoryMethod, targetType).filter(Objects::nonNull).toArray();
1868				}
1869				catch (NoSuchBeanDefinitionException ex) {
1870					return null;
1871				}
1872			}
1873	
1874		}
