33	/**
34	 * A collection of {@link SpringApplicationRunListener}.
35	 *
36	 * @author Phillip Webb
37	 * @author Andy Wilkinson
38	 * @author Chris Bono
39	 */
40	class SpringApplicationRunListeners {
41	
42		private final Log log;
43	
44		private final List<SpringApplicationRunListener> listeners;
45	
46		private final ApplicationStartup applicationStartup;
47	
48		SpringApplicationRunListeners(Log log, List<SpringApplicationRunListener> listeners,
49				ApplicationStartup applicationStartup) {
50			this.log = log;
51			this.listeners = List.copyOf(listeners);
52			this.applicationStartup = applicationStartup;
53		}
54	
55		void starting(ConfigurableBootstrapContext bootstrapContext, @Nullable Class<?> mainApplicationClass) {
56			doWithListeners("spring.boot.application.starting", (listener) -> listener.starting(bootstrapContext),
57					(step) -> {
58						if (mainApplicationClass != null) {
59							step.tag("mainApplicationClass", mainApplicationClass.getName());
60						}
61					});
62		}
63	
64		void environmentPrepared(ConfigurableBootstrapContext bootstrapContext, ConfigurableEnvironment environment) {
65			doWithListeners("spring.boot.application.environment-prepared",
66					(listener) -> listener.environmentPrepared(bootstrapContext, environment));
67		}
68	
69		void contextPrepared(ConfigurableApplicationContext context) {
70			doWithListeners("spring.boot.application.context-prepared", (listener) -> listener.contextPrepared(context));
71		}
72	
73		void contextLoaded(ConfigurableApplicationContext context) {
74			doWithListeners("spring.boot.application.context-loaded", (listener) -> listener.contextLoaded(context));
75		}
76	
77		void started(ConfigurableApplicationContext context, Duration timeTaken) {
78			doWithListeners("spring.boot.application.started", (listener) -> listener.started(context, timeTaken));
79		}
80	
81		void ready(ConfigurableApplicationContext context, Duration timeTaken) {
82			doWithListeners("spring.boot.application.ready", (listener) -> listener.ready(context, timeTaken));
83		}
84	
85		void failed(@Nullable ConfigurableApplicationContext context, Throwable exception) {
86			doWithListeners("spring.boot.application.failed",
87					(listener) -> callFailedListener(listener, context, exception), (step) -> {
88						step.tag("exception", exception.getClass().toString());
89						String message = exception.getMessage();
90						if (message != null) {
91							step.tag("message", message);
92						}
93					});
94		}
95	
96		private void callFailedListener(SpringApplicationRunListener listener,
97				@Nullable ConfigurableApplicationContext context, Throwable exception) {
98			try {
99				listener.failed(context, exception);
100			}
101			catch (Throwable ex) {
102				if (exception == null) {
103					ReflectionUtils.rethrowRuntimeException(ex);
104				}
105				if (this.log.isDebugEnabled()) {
106					this.log.error("Error handling failed", ex);
107				}
108				else {
109					String message = ex.getMessage();
110					message = (message != null) ? message : "no error message";
111					this.log.warn("Error handling failed (" + message + ")");
112				}
113			}
114		}
115	
116		private void doWithListeners(String stepName, Consumer<SpringApplicationRunListener> listenerAction) {
117			doWithListeners(stepName, listenerAction, null);
118		}
119	
120		private void doWithListeners(String stepName, Consumer<SpringApplicationRunListener> listenerAction,
121				@Nullable Consumer<StartupStep> stepAction) {
122			StartupStep step = this.applicationStartup.start(stepName);
123			this.listeners.forEach(listenerAction);
124			if (stepAction != null) {
125				stepAction.accept(step);
126			}
127			step.end();
128		}
129	
130	}
