137		 * Return the {@link AutoConfigurationEntry} based on the {@link AnnotationMetadata}
138		 * of the importing {@link Configuration @Configuration} class.
139		 * @param annotationMetadata the annotation metadata of the configuration class
140		 * @return the auto-configurations that should be imported
141		 */
142		protected AutoConfigurationEntry getAutoConfigurationEntry(AnnotationMetadata annotationMetadata) {
143			if (!isEnabled(annotationMetadata)) {
144				return EMPTY_ENTRY;
145			}
146			AnnotationAttributes attributes = getAttributes(annotationMetadata);
147			List<String> configurations = getCandidateConfigurations(annotationMetadata, attributes);
148			configurations = removeDuplicates(configurations);
149			Set<String> exclusions = getExclusions(annotationMetadata, attributes);
150			checkExcludedClasses(configurations, exclusions);

150			checkExcludedClasses(configurations, exclusions);
151			configurations.removeAll(exclusions);
152			configurations = getConfigurationClassFilter().filter(configurations);
153			fireAutoConfigurationImportEvents(configurations, exclusions);
154			return new AutoConfigurationEntry(configurations, exclusions);
155		}
