212		private void checkExcludedClasses(List<String> configurations, Set<String> exclusions) {
213			List<String> invalidExcludes = new ArrayList<>(exclusions.size());
214			ClassLoader classLoader = (this.beanClassLoader != null) ? this.beanClassLoader : getClass().getClassLoader();
215			for (String exclusion : exclusions) {
216				if (ClassUtils.isPresent(exclusion, classLoader) && !configurations.contains(exclusion)) {
217					invalidExcludes.add(exclusion);
218				}
219			}
220			if (!invalidExcludes.isEmpty()) {
221				handleInvalidExcludes(invalidExcludes);
222			}
223		}
