225		/**
226		 * Handle any invalid excludes that have been specified.
227		 * @param invalidExcludes the list of invalid excludes (will always have at least one
228		 * element)
229		 */
230		protected void handleInvalidExcludes(List<String> invalidExcludes) {
231			StringBuilder message = new StringBuilder();
232			for (String exclude : invalidExcludes) {
233				message.append("\t- ").append(exclude).append(String.format("%n"));
234			}
235			throw new IllegalStateException(String.format(
236					"The following classes could not be excluded because they are not auto-configuration classes:%n%s",
237					message));
238		}
