240		/**
241		 * Return any exclusions that limit the candidate configurations.
242		 * @param metadata the source metadata
243		 * @param attributes the {@link #getAttributes(AnnotationMetadata) annotation
244		 * attributes}
245		 * @return exclusions or an empty set
246		 */
247		protected Set<String> getExclusions(AnnotationMetadata metadata, @Nullable AnnotationAttributes attributes) {
248			Set<String> excluded = new LinkedHashSet<>();
249			if (attributes != null) {
250				excluded.addAll(asList(attributes, "exclude"));
251				excluded.addAll(asList(attributes, "excludeName"));
252			}
253			excluded.addAll(getExcludeAutoConfigurationsProperty());
254			return getAutoConfigurationReplacements().replaceAll(excluded);
255		}
