42	 * @author Scott Frederick
43	 * @since 2.7.0
44	 */
45	public final class ImportCandidates implements Iterable<String> {
46	
47		private static final String LOCATION = "META-INF/spring/%s.imports";
48	
49		private static final String COMMENT_START = "#";
50	
51		private final List<String> candidates;
52	
53		private ImportCandidates(List<String> candidates) {
54			Assert.notNull(candidates, "'candidates' must not be null");
55			this.candidates = Collections.unmodifiableList(candidates);
56		}
57	
