71		/**
72		 * Loads the names of import candidates from the classpath. The names of the import
73		 * candidates are stored in files named
74		 * {@code META-INF/spring/full-qualified-annotation-name.imports} on the classpath.
75		 * Every line contains the full qualified name of the candidate class. Comments are
76		 * supported using the # character.
77		 * @param annotation annotation to load
78		 * @param classLoader class loader to use for loading
79		 * @return list of names of annotated classes
80		 */
81		public static ImportCandidates load(Class<?> annotation, @Nullable ClassLoader classLoader) {
82			Assert.notNull(annotation, "'annotation' must not be null");
83			ClassLoader classLoaderToUse = decideClassloader(classLoader);
84			String location = String.format(LOCATION, annotation.getName());
85			Enumeration<URL> urls = findUrlsInClasspath(classLoaderToUse, location);
86			List<String> importCandidates = new ArrayList<>();
87			while (urls.hasMoreElements()) {
88				URL url = urls.nextElement();
89				importCandidates.addAll(readCandidateConfigurations(url));
90			}
91			return new ImportCandidates(importCandidates);
92		}
93	
94		private static ClassLoader decideClassloader(@Nullable ClassLoader classLoader) {
95			if (classLoader == null) {
96				return ImportCandidates.class.getClassLoader();
97			}
98			return classLoader;
99		}
100	
101		private static Enumeration<URL> findUrlsInClasspath(ClassLoader classLoader, String location) {
102			try {
103				return classLoader.getResources(location);
104			}
105			catch (IOException ex) {
106				throw new IllegalArgumentException("Failed to load configurations from location [" + location + "]", ex);
107			}
108		}
109	
110		private static List<String> readCandidateConfigurations(URL url) {
111			try (BufferedReader reader = new BufferedReader(
112					new InputStreamReader(new UrlResource(url).getInputStream(), StandardCharsets.UTF_8))) {
113				List<String> candidates = new ArrayList<>();
114				String line;
115				while ((line = reader.readLine()) != null) {
116					line = stripComment(line);
117					line = line.trim();
118					if (line.isEmpty()) {
119						continue;
120					}
121					candidates.add(line);
122				}
123				return candidates;
124			}
125			catch (IOException ex) {
126				throw new IllegalArgumentException("Unable to load configurations from location [" + url + "]", ex);
127			}
128		}
129	
130		private static String stripComment(String line) {
131			int commentStart = line.indexOf(COMMENT_START);
132			if (commentStart == -1) {
133				return line;
134			}
135			return line.substring(0, commentStart);
136		}
