388		private static class ConfigurationClassFilter {
389	
390			private final AutoConfigurationMetadata autoConfigurationMetadata;
391	
392			private final List<AutoConfigurationImportFilter> filters;
393	
394			ConfigurationClassFilter(ClassLoader classLoader, List<AutoConfigurationImportFilter> filters) {
395				this.autoConfigurationMetadata = AutoConfigurationMetadataLoader.loadMetadata(classLoader);
396				this.filters = filters;
397			}
398	
399			List<String> filter(List<String> configurations) {
400				long startTime = System.nanoTime();
401				@Nullable String[] candidates = StringUtils.toStringArray(configurations);
402				boolean skipped = false;
403				for (AutoConfigurationImportFilter filter : this.filters) {
404					boolean[] match = filter.match(candidates, this.autoConfigurationMetadata);
405					for (int i = 0; i < match.length; i++) {
406						if (!match[i]) {
407							candidates[i] = null;
408							skipped = true;
409						}
410					}
411				}
412				if (!skipped) {
413					return configurations;
414				}
415				List<String> result = new ArrayList<>(candidates.length);
416				for (String candidate : candidates) {
417					if (candidate != null) {
418						result.add(candidate);
419					}
420				}
421				if (logger.isTraceEnabled()) {
422					int numberFiltered = configurations.size() - result.size();
423					logger.trace("Filtered " + numberFiltered + " auto configuration class in "
424							+ TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime) + " ms");
425				}
426				return result;
427			}
428	
429		}
