53	public abstract class AutoConfigurationPackages {
54	
55		private static final Log logger = LogFactory.getLog(AutoConfigurationPackages.class);
56	
57		private static final String BEAN = AutoConfigurationPackages.class.getName();
58	
59		/**
60		 * Determine if the auto-configuration base packages for the given bean factory are
61		 * available.
62		 * @param beanFactory the source bean factory
63		 * @return true if there are auto-config packages available
64		 */
65		public static boolean has(BeanFactory beanFactory) {
66			return beanFactory.containsBean(BEAN) && !get(beanFactory).isEmpty();
67		}
