69		/**
70		 * Return the auto-configuration base packages for the given bean factory.
71		 * @param beanFactory the source bean factory
72		 * @return a list of auto-configuration packages
73		 * @throws IllegalStateException if auto-configuration is not enabled
74		 */
75		public static List<String> get(BeanFactory beanFactory) {
76			try {
77				return beanFactory.getBean(BEAN, BasePackages.class).get();
78			}
79			catch (NoSuchBeanDefinitionException ex) {
80				throw new IllegalStateException("Unable to retrieve @EnableAutoConfiguration base packages");
81			}
