84		/**
85		 * Programmatically registers the auto-configuration package names. Subsequent
86		 * invocations will add the given package names to those that have already been
87		 * registered. You can use this method to manually define the base packages that will
88		 * be used for a given {@link BeanDefinitionRegistry}. Generally it's recommended that
89		 * you don't call this method directly, but instead rely on the default convention
90		 * where the package name is set from your {@code @EnableAutoConfiguration}
91		 * configuration class or classes.
92		 * @param registry the bean definition registry
93		 * @param packageNames the package names to set
94		 */
95		public static void register(BeanDefinitionRegistry registry, String... packageNames) {
96			if (registry.containsBeanDefinition(BEAN)) {
97				addBasePackages(registry.getBeanDefinition(BEAN), packageNames);
98			}
99			else {
100				RootBeanDefinition beanDefinition = new RootBeanDefinition(BasePackages.class);
101				beanDefinition.setRole(BeanDefinition.ROLE_INFRASTRUCTURE);
102				addBasePackages(beanDefinition, packageNames);
103				registry.registerBeanDefinition(BEAN, beanDefinition);
104			}
105		}
