107		private static void addBasePackages(BeanDefinition beanDefinition, String[] additionalBasePackages) {
108			ConstructorArgumentValues constructorArgumentValues = beanDefinition.getConstructorArgumentValues();
109			if (constructorArgumentValues.hasIndexedArgumentValue(0)) {
110				ValueHolder indexedArgumentValue = constructorArgumentValues.getIndexedArgumentValue(0, String[].class);
111				Assert.state(indexedArgumentValue != null, "'indexedArgumentValue' must not be null");
112				String[] existingPackages = (String[]) indexedArgumentValue.getValue();
113				Stream<String> existingPackagesStream = (existingPackages != null) ? Stream.of(existingPackages)
114						: Stream.empty();
115				constructorArgumentValues.addIndexedArgumentValue(0,
116						Stream.concat(existingPackagesStream, Stream.of(additionalBasePackages))
117							.distinct()
118							.toArray(String[]::new));
119			}
120			else {
121				constructorArgumentValues.addIndexedArgumentValue(0, additionalBasePackages);
122			}
123		}
