36	public class StandardConfigDataLoader implements ConfigDataLoader<StandardConfigDataResource> {
37	
38		private static final PropertySourceOptions PROFILE_SPECIFIC = PropertySourceOptions.always(Option.PROFILE_SPECIFIC);
39	
40		private static final PropertySourceOptions NON_PROFILE_SPECIFIC = PropertySourceOptions.ALWAYS_NONE;
41	
42		@Override
43		public ConfigData load(ConfigDataLoaderContext context, StandardConfigDataResource resource)
44				throws IOException, ConfigDataNotFoundException {
45			if (resource.isEmptyDirectory()) {
46				return ConfigData.EMPTY;
47			}
48			ConfigDataResourceNotFoundException.throwIfDoesNotExist(resource, resource.getResource());
49			StandardConfigDataReference reference = resource.getReference();
50			Resource originTrackedResource = OriginTrackedResource.of(resource.getResource(),
51					Origin.from(reference.getConfigDataLocation()));
52			String name = String.format("Config resource '%s' via location '%s'", resource,
53					reference.getConfigDataLocation());
54			List<PropertySource<?>> propertySources = reference.getPropertySourceLoader()
55				.load(name, originTrackedResource, reference.getEncoding());
56			PropertySourceOptions options = (resource.getProfile() != null) ? PROFILE_SPECIFIC : NON_PROFILE_SPECIFIC;
57			return new ConfigData(propertySources, options);
58		}
