56		private <T> void register(Class<T> type, InstanceSupplier<T> instanceSupplier, boolean replaceExisting) {
57			Assert.notNull(type, "'type' must not be null");
58			Assert.notNull(instanceSupplier, "'instanceSupplier' must not be null");
59			synchronized (this.instanceSuppliers) {
60				boolean alreadyRegistered = this.instanceSuppliers.containsKey(type);
