100			for (int i = 0; i < outcomes.length; i++) {
101				String autoConfigurationClass = autoConfigurationClasses[i];
102				if (autoConfigurationClass != null) {
103					Set<String> onBeanTypes = autoConfigurationMetadata.getSet(autoConfigurationClass, "ConditionalOnBean");
104					outcomes[i] = getOutcome(onBeanTypes, ConditionalOnBean.class);
105					if (outcomes[i] == null) {
106						Set<String> onSingleCandidateTypes = autoConfigurationMetadata.getSet(autoConfigurationClass,
