117			List<String> missing = filter(requiredBeanTypes, ClassNameFilter.MISSING, getBeanClassLoader());
118			if (!missing.isEmpty()) {
119				ConditionMessage message = ConditionMessage.forCondition(annotation)
120					.didNotFind("required type", "required types")
121					.items(Style.QUOTE, missing);
122				return ConditionOutcome.noMatch(message);
123			}
