56		public ConditionOutcome getMatchOutcome(ConditionContext context, AnnotatedTypeMetadata metadata) {
57			MergedAnnotations mergedAnnotations = metadata.getAnnotations();
58			List<MergedAnnotation<Annotation>> annotations = stream(mergedAnnotations).toList();
59			List<ConditionMessage> noMatch = new ArrayList<>();
60			List<ConditionMessage> match = new ArrayList<>();
61			for (MergedAnnotation<Annotation> annotation : annotations) {
62				ConditionOutcome outcome = determineOutcome(annotation, context.getEnvironment());
63				(outcome.isMatch() ? match : noMatch).add(outcome.getConditionMessage());
64			}
65			if (!noMatch.isEmpty()) {
66				return ConditionOutcome.noMatch(ConditionMessage.of(noMatch));
67			}
68			return ConditionOutcome.match(ConditionMessage.of(match));
69		}
