99		private ConditionOutcome determineOutcome(MergedAnnotation<Annotation> annotation, PropertyResolver resolver) {
100			Class<Annotation> annotationType = annotation.getType();
101			Spec spec = new Spec(annotationType, annotation.asAnnotationAttributes());
102			List<String> missingProperties = new ArrayList<>();
103			List<String> nonMatchingProperties = new ArrayList<>();
104			spec.collectProperties(resolver, missingProperties, nonMatchingProperties);
105			if (!missingProperties.isEmpty()) {
106				return ConditionOutcome.noMatch(ConditionMessage.forCondition(annotationType, spec)
107					.didNotFind("property", "properties")
108					.items(Style.QUOTE, missingProperties));
109			}
110			if (!nonMatchingProperties.isEmpty()) {
111				return ConditionOutcome.noMatch(ConditionMessage.forCondition(annotationType, spec)
112					.found("different value in property", "different value in properties")
113					.items(Style.QUOTE, nonMatchingProperties));
114			}
115			return ConditionOutcome.match(ConditionMessage.forCondition(annotationType, spec).because("matched"));
116		}
