642		 * @param context the application context
643		 */
644		protected void logStartupProfileInfo(ConfigurableApplicationContext context) {
645			Log log = getApplicationLog();
646			if (log.isInfoEnabled()) {
647				List<String> activeProfiles = quoteProfiles(context.getEnvironment().getActiveProfiles());
648				if (ObjectUtils.isEmpty(activeProfiles)) {
649					List<String> defaultProfiles = quoteProfiles(context.getEnvironment().getDefaultProfiles());
650					String message = String.format("%s default %s: ", defaultProfiles.size(),
651							(defaultProfiles.size() <= 1) ? "profile" : "profiles");
652					log.info("No active profile set, falling back to " + message
653							+ StringUtils.collectionToDelimitedString(defaultProfiles, ", "));
654				}
655				else {
656					String message = (activeProfiles.size() == 1) ? "1 profile is active: "
657							: activeProfiles.size() + " profiles are active: ";
658					log.info("The following " + message + StringUtils.collectionToDelimitedString(activeProfiles, ", "));
659				}
660			}
661		}
