796		@SuppressWarnings("unchecked")
797		private <R extends Runner> void callRunner(Class<R> type, Runner runner, ThrowingConsumer<R> call) {
798			call.throwing(
799					(message, ex) -> new IllegalStateException("Failed to execute " + ClassUtils.getShortName(type), ex))
800				.accept((R) runner);
801		}
