881		private void handleExitCode(@Nullable ConfigurableApplicationContext context, Throwable exception) {
882			int exitCode = getExitCodeFromException(context, exception);
883			if (exitCode != 0) {
884				if (context != null) {
885					context.publishEvent(new ExitCodeEvent(context, exitCode));
886				}
887				SpringBootExceptionHandler handler = getSpringBootExceptionHandler();
888				if (handler != null) {
889					handler.registerExitCode(exitCode);
890				}
891			}
892		}
