77		private <T> @Nullable T getFromSpringFactories(@Nullable WebApplicationType webApplicationType,
78				BiFunction<ApplicationContextFactory, @Nullable WebApplicationType, @Nullable T> action,
79				@Nullable Supplier<T> defaultResult) {
80			for (ApplicationContextFactory candidate : SpringFactoriesLoader.loadFactories(ApplicationContextFactory.class,
81					getClass().getClassLoader())) {
82				T result = action.apply(candidate, webApplicationType);
83				if (result != null) {
