50	/**
51	 * Wrapper around a {@link ConfigurableEnvironment} that can be used to import and apply
52	 * {@link ConfigData}. Configures the initial set of
53	 * {@link ConfigDataEnvironmentContributors} by wrapping property sources from the Spring
54	 * {@link Environment} and adding the initial set of locations.
55	 * <p>
56	 * The initial locations can be influenced through the {@link #LOCATION_PROPERTY},
57	 * {@value #ADDITIONAL_LOCATION_PROPERTY} and {@value #IMPORT_PROPERTY} properties. If no
58	 * explicit properties are set, the {@link #DEFAULT_SEARCH_LOCATIONS} will be used.
59	 *
60	 * @author Phillip Webb
61	 * @author Madhura Bhave
62	 * @author Nan Chiu
63	 */
64	class ConfigDataEnvironment {
65	
66		/**
67		 * Property used override the imported locations.
68		 */
69		static final String LOCATION_PROPERTY = "spring.config.location";
70	
71		/**
72		 * Property used to provide additional locations to import.
73		 */
74		static final String ADDITIONAL_LOCATION_PROPERTY = "spring.config.additional-location";
75	
76		/**
77		 * Property used to provide additional locations to import.
78		 */
79		static final String IMPORT_PROPERTY = "spring.config.import";
80	
81		/**
82		 * Property used to determine what action to take when a
83		 * {@code ConfigDataNotFoundAction} is thrown.
84		 * @see ConfigDataNotFoundAction
85		 */
86		static final String ON_NOT_FOUND_PROPERTY = "spring.config.on-not-found";
87	
88		/**
89		 * Default search locations used if not {@link #LOCATION_PROPERTY} is found.
90		 */
91		static final ConfigDataLocation[] DEFAULT_SEARCH_LOCATIONS;
92		static {
93			List<ConfigDataLocation> locations = new ArrayList<>();
94			locations.add(ConfigDataLocation.of("optional:classpath:/;optional:classpath:/config/"));
95			locations.add(ConfigDataLocation.of("optional:file:./;optional:file:./config/;optional:file:./config/*/"));
96			DEFAULT_SEARCH_LOCATIONS = locations.toArray(new ConfigDataLocation[0]);
97		}
98	
99		private static final ConfigDataLocation[] EMPTY_LOCATIONS = new ConfigDataLocation[0];
100	
101		private static final Bindable<ConfigDataLocation[]> CONFIG_DATA_LOCATION_ARRAY = Bindable
102			.of(ConfigDataLocation[].class);
103	
104		private static final Bindable<List<String>> STRING_LIST = Bindable.listOf(String.class);
105	
106		private static final BinderOption[] ALLOW_INACTIVE_BINDING = {};
107	
108		private static final BinderOption[] DENY_INACTIVE_BINDING = { BinderOption.FAIL_ON_BIND_TO_INACTIVE_SOURCE };
109	
110		private final DeferredLogFactory logFactory;
111	
112		private final Log logger;
113	
114		private final ConfigDataNotFoundAction notFoundAction;
115	
116		private final ConfigurableBootstrapContext bootstrapContext;
117	
118		private final ConfigurableEnvironment environment;
119	
120		private final ConfigDataLocationResolvers resolvers;
121	
122		private final Collection<String> additionalProfiles;
123	
124		private final ConfigDataEnvironmentUpdateListener environmentUpdateListener;
125	
126		private final ConfigDataLoaders loaders;
127	
128		private final ConfigDataEnvironmentContributors contributors;
