130		/**
131		 * Create a new {@link ConfigDataEnvironment} instance.
132		 * @param logFactory the deferred log factory
133		 * @param bootstrapContext the bootstrap context
134		 * @param environment the Spring {@link Environment}.
135		 * @param resourceLoader {@link ResourceLoader} to load resource locations
136		 * @param additionalProfiles any additional profiles to activate
137		 * @param environmentUpdateListener optional
138		 * {@link ConfigDataEnvironmentUpdateListener} that can be used to track
139		 * {@link Environment} updates.
140		 */
141		ConfigDataEnvironment(DeferredLogFactory logFactory, ConfigurableBootstrapContext bootstrapContext,
142				ConfigurableEnvironment environment, ResourceLoader resourceLoader, Collection<String> additionalProfiles,
143				@Nullable ConfigDataEnvironmentUpdateListener environmentUpdateListener) {
144			Binder binder = Binder.get(environment);
145			this.logFactory = logFactory;
146			this.logger = logFactory.getLog(getClass());
147			this.notFoundAction = binder.bind(ON_NOT_FOUND_PROPERTY, ConfigDataNotFoundAction.class)
148				.orElse(ConfigDataNotFoundAction.FAIL);
149			this.bootstrapContext = bootstrapContext;
150			this.environment = environment;
151			this.resolvers = createConfigDataLocationResolvers(logFactory, bootstrapContext, binder, resourceLoader);
152			this.additionalProfiles = additionalProfiles;
153			this.environmentUpdateListener = (environmentUpdateListener != null) ? environmentUpdateListener
154					: ConfigDataEnvironmentUpdateListener.NONE;
155			this.loaders = new ConfigDataLoaders(logFactory, bootstrapContext,
156					SpringFactoriesLoader.forDefaultResourceLocation(resourceLoader.getClassLoader()));
157			this.contributors = createContributors(binder);
158		}
