160		protected ConfigDataLocationResolvers createConfigDataLocationResolvers(DeferredLogFactory logFactory,
161				ConfigurableBootstrapContext bootstrapContext, Binder binder, ResourceLoader resourceLoader) {
162			return new ConfigDataLocationResolvers(logFactory, bootstrapContext, binder, resourceLoader,
163					SpringFactoriesLoader.forDefaultResourceLocation(resourceLoader.getClassLoader()));
164		}
