166		private ConfigDataEnvironmentContributors createContributors(Binder binder) {
167			this.logger.trace("Building config data environment contributors");
168			MutablePropertySources propertySources = this.environment.getPropertySources();
169			List<ConfigDataEnvironmentContributor> contributors = new ArrayList<>(propertySources.size() + 10);
170			PropertySource<?> defaultPropertySource = null;
171			for (PropertySource<?> propertySource : propertySources) {
172				if (DefaultPropertiesPropertySource.hasMatchingName(propertySource)) {
173					defaultPropertySource = propertySource;
174				}
175				else {
176					this.logger.trace(LogMessage.format("Creating wrapped config data contributor for '%s'",
177							propertySource.getName()));
178					contributors.add(ConfigDataEnvironmentContributor.ofExisting(propertySource,
179							this.environment.getConversionService()));
180				}
181			}
182			contributors.addAll(getInitialImportContributors(binder));
183			if (defaultPropertySource != null) {
184				this.logger.trace("Creating wrapped config data contributor for default property source");
185				contributors.add(ConfigDataEnvironmentContributor.ofExisting(defaultPropertySource,
186						this.environment.getConversionService()));
187			}
188			return createContributors(contributors);
189		}
190	
191		protected ConfigDataEnvironmentContributors createContributors(
192				List<ConfigDataEnvironmentContributor> contributors) {
193			return new ConfigDataEnvironmentContributors(this.logFactory, this.bootstrapContext, contributors,
194					this.environment.getConversionService(), this.environmentUpdateListener);
195		}
