232		/**
233		 * Process all contributions and apply any newly imported property sources to the
234		 * {@link Environment}.
235		 */
236		void processAndApply() {
237			ConfigDataImporter importer = new ConfigDataImporter(this.logFactory, this.notFoundAction, this.resolvers,
238					this.loaders);
239			registerBootstrapBinder(this.contributors, null, DENY_INACTIVE_BINDING);
240			ConfigDataEnvironmentContributors contributors = processInitial(this.contributors, importer);
241			ConfigDataActivationContext activationContext = createActivationContext(
242					contributors.getBinder(null, BinderOption.FAIL_ON_BIND_TO_INACTIVE_SOURCE));
243			contributors = processWithoutProfiles(contributors, importer, activationContext);
244			activationContext = withProfiles(contributors, activationContext);
245			contributors = processWithProfiles(contributors, importer, activationContext);
246			applyToEnvironment(contributors, activationContext, importer.getLoadedLocations(),
247					importer.getOptionalLocations());
248		}
249	
250		private ConfigDataEnvironmentContributors processInitial(ConfigDataEnvironmentContributors contributors,
251				ConfigDataImporter importer) {
252			this.logger.trace("Processing initial config data environment contributors without activation context");
253			contributors = contributors.withProcessedImports(importer, null);
254			registerBootstrapBinder(contributors, null, DENY_INACTIVE_BINDING);
255			return contributors;
256		}
257	
258		private ConfigDataActivationContext createActivationContext(Binder initialBinder) {
259			this.logger.trace("Creating config data activation context from initial contributions");
260			try {
261				return new ConfigDataActivationContext(this.environment, initialBinder);
262			}
263			catch (BindException ex) {
264				if (ex.getCause() instanceof InactiveConfigDataAccessException inactiveException) {
265					throw inactiveException;
266				}
267				throw ex;
268			}
269		}
270	
271		private ConfigDataEnvironmentContributors processWithoutProfiles(ConfigDataEnvironmentContributors contributors,
272				ConfigDataImporter importer, ConfigDataActivationContext activationContext) {
273			this.logger.trace("Processing config data environment contributors with initial activation context");
274			contributors = contributors.withProcessedImports(importer, activationContext);
275			registerBootstrapBinder(contributors, activationContext, DENY_INACTIVE_BINDING);
276			return contributors;
277		}
278	
279		private ConfigDataActivationContext withProfiles(ConfigDataEnvironmentContributors contributors,
280				ConfigDataActivationContext activationContext) {
281			this.logger.trace("Deducing profiles from current config data environment contributors");
282			Binder binder = contributors.getBinder(activationContext,
283					(contributor) -> !contributor.hasConfigDataOption(ConfigData.Option.IGNORE_PROFILES),
284					BinderOption.FAIL_ON_BIND_TO_INACTIVE_SOURCE);
285			try {
286				Set<String> additionalProfiles = new LinkedHashSet<>(this.additionalProfiles);
287				additionalProfiles.addAll(getIncludedProfiles(contributors, activationContext));
288				Profiles profiles = new Profiles(this.environment, binder, additionalProfiles);
289				return activationContext.withProfiles(profiles);
290			}
291			catch (BindException ex) {
292				if (ex.getCause() instanceof InactiveConfigDataAccessException inactiveException) {
293					throw inactiveException;
294				}
295				throw ex;
296			}
297		}
