60	public class StandardConfigDataLocationResolver
61			implements ConfigDataLocationResolver<StandardConfigDataResource>, Ordered {
62	
63		private static final String PREFIX = "resource:";
64	
65		static final String CONFIG_NAME_PROPERTY = "spring.config.name";
66	
67		static final String[] DEFAULT_CONFIG_NAMES = { "application" };
68	
69		private static final Pattern URL_PREFIX = Pattern.compile("^([a-zA-Z][a-zA-Z0-9*]*?:)(.*$)");
70	
71		private static final @Nullable String NO_PROFILE = null;
72	
73		private final Log logger;
74	
75		private final List<PropertySourceLoader> propertySourceLoaders;
76	
77		private final String[] configNames;
78	
79		private final LocationResourceLoader resourceLoader;
80	
81		/**
82		 * Create a new {@link StandardConfigDataLocationResolver} instance.
83		 * @param logFactory the factory for loggers to use
84		 * @param binder a binder backed by the initial {@link Environment}
85		 * @param resourceLoader a {@link ResourceLoader} used to load resources
86		 */
87		public StandardConfigDataLocationResolver(DeferredLogFactory logFactory, Binder binder,
88				ResourceLoader resourceLoader) {
89			this.logger = logFactory.getLog(StandardConfigDataLocationResolver.class);
90			this.propertySourceLoaders = SpringFactoriesLoader.loadFactories(PropertySourceLoader.class,
91					resourceLoader.getClassLoader());
92			this.configNames = getConfigNames(binder);
93			this.resourceLoader = new LocationResourceLoader(resourceLoader);
94		}
95	
96		private String[] getConfigNames(Binder binder) {
97			String[] configNames = binder.bind(CONFIG_NAME_PROPERTY, String[].class).orElse(DEFAULT_CONFIG_NAMES);
98			for (String configName : configNames) {
99				validateConfigName(configName);
100			}
101			return configNames;
102		}
103	
104		private void validateConfigName(String name) {
105			Assert.state(!name.contains("*"), () -> "Config name '" + name + "' cannot contain '*'");
106		}
107	
108		@Override
109		public int getOrder() {
110			return Ordered.LOWEST_PRECEDENCE;
111		}
112	
113		@Override
114		public boolean isResolvable(ConfigDataLocationResolverContext context, ConfigDataLocation location) {
115			return true;
116		}
117	
118		@Override
119		public List<StandardConfigDataResource> resolve(ConfigDataLocationResolverContext context,
120				ConfigDataLocation location) throws ConfigDataNotFoundException {
121			return resolve(getReferences(context, location.split()));
122		}
123	
124		private Set<StandardConfigDataReference> getReferences(ConfigDataLocationResolverContext context,
125				ConfigDataLocation[] configDataLocations) {
126			Set<StandardConfigDataReference> references = new LinkedHashSet<>();
127			for (ConfigDataLocation configDataLocation : configDataLocations) {
128				references.addAll(getReferences(context, configDataLocation));
129			}
130			return references;
131		}
132	
133		private Set<StandardConfigDataReference> getReferences(ConfigDataLocationResolverContext context,
134				ConfigDataLocation configDataLocation) {
135			String resourceLocation = getResourceLocation(context, configDataLocation);
136			try {
137				if (isDirectory(resourceLocation)) {
138					return getReferencesForDirectory(configDataLocation, resourceLocation, NO_PROFILE);
139				}
140				return getReferencesForFile(configDataLocation, resourceLocation, NO_PROFILE);
141			}
142			catch (RuntimeException ex) {
143				throw new IllegalStateException("Unable to load config data from '" + configDataLocation + "'", ex);
144			}
145		}
146	
147		@Override
148		public List<StandardConfigDataResource> resolveProfileSpecific(ConfigDataLocationResolverContext context,
149				ConfigDataLocation location, Profiles profiles) {
150			return resolve(getProfileSpecificReferences(context, location.split(), profiles));
151		}
152	
153		private Set<StandardConfigDataReference> getProfileSpecificReferences(ConfigDataLocationResolverContext context,
154				ConfigDataLocation[] configDataLocations, Profiles profiles) {
155			Set<StandardConfigDataReference> references = new LinkedHashSet<>();
156			for (String profile : profiles) {
157				for (ConfigDataLocation configDataLocation : configDataLocations) {
158					String resourceLocation = getResourceLocation(context, configDataLocation);
159					references.addAll(getReferences(configDataLocation, resourceLocation, profile));
160				}
161			}
162			return references;
163		}
164	
165		private String getResourceLocation(ConfigDataLocationResolverContext context,
166				ConfigDataLocation configDataLocation) {
167			String resourceLocation = configDataLocation.getNonPrefixedValue(PREFIX);
168			boolean isFixedPath = resourceLocation.startsWith("/") || URL_PREFIX.matcher(resourceLocation).matches();
169			if (isFixedPath) {
170				return resourceLocation;
171			}
172			ConfigDataResource parent = context.getParent();
173			if (parent instanceof StandardConfigDataResource resource) {
174				String parentResourceLocation = resource.getReference().getResourceLocation();
175				String parentDirectory = parentResourceLocation.substring(0, parentResourceLocation.lastIndexOf("/") + 1);
176				return parentDirectory + resourceLocation;
177			}
178			return resourceLocation;
179		}
180	
181		private Set<StandardConfigDataReference> getReferences(ConfigDataLocation configDataLocation,
182				String resourceLocation, String profile) {
183			if (isDirectory(resourceLocation)) {
184				return getReferencesForDirectory(configDataLocation, resourceLocation, profile);
185			}
186			return getReferencesForFile(configDataLocation, resourceLocation, profile);
187		}
188	
189		private Set<StandardConfigDataReference> getReferencesForDirectory(ConfigDataLocation configDataLocation,
190				String directory, @Nullable String profile) {
191			Set<StandardConfigDataReference> references = new LinkedHashSet<>();
192			for (String name : this.configNames) {
193				Deque<StandardConfigDataReference> referencesForName = getReferencesForConfigName(name, configDataLocation,
194						directory, profile);
195				references.addAll(referencesForName);
196			}
197			return references;
198		}
199	
200		private Deque<StandardConfigDataReference> getReferencesForConfigName(String name,
201				ConfigDataLocation configDataLocation, String directory, @Nullable String profile) {
202			Deque<StandardConfigDataReference> references = new ArrayDeque<>();
203			for (PropertySourceLoader propertySourceLoader : this.propertySourceLoaders) {
204				for (String extension : propertySourceLoader.getFileExtensions()) {
205					StandardConfigDataReference reference = new StandardConfigDataReference(configDataLocation, directory,
206							directory + name, profile, extension, propertySourceLoader, null);
207					if (!references.contains(reference)) {
208						references.addFirst(reference);
209					}
210				}
211			}
212			return references;
213		}
214	
215		private Set<StandardConfigDataReference> getReferencesForFile(ConfigDataLocation configDataLocation, String file,
216				@Nullable String profile) {
217			FileHint fileHint = FileHint.from(file);
218			file = FileHint.removeFrom(file);
219			boolean hasFileHintExtension = fileHint.getExtension() != null;
220			if (hasFileHintExtension) {
221				file = file + fileHint.getExtension();
222			}
223			for (PropertySourceLoader propertySourceLoader : this.propertySourceLoaders) {
224				String fileExtension = getLoadableFileExtension(propertySourceLoader, file);
225				if (fileExtension != null) {
226					String root = file.substring(0, file.length() - fileExtension.length() - 1);
227					StandardConfigDataReference reference = new StandardConfigDataReference(configDataLocation, null, root,
228							profile, (!hasFileHintExtension) ? fileExtension : null, propertySourceLoader,
229							fileHint.getEncodingAsCharset());
230					return Collections.singleton(reference);
231				}
232			}
233			if (configDataLocation.isOptional()) {
234				return Collections.emptySet();
235			}
236			if (configDataLocation.hasPrefix(PREFIX) || configDataLocation.hasPrefix(ResourceUtils.FILE_URL_PREFIX)
237					|| configDataLocation.hasPrefix(ResourceUtils.CLASSPATH_URL_PREFIX)
238					|| configDataLocation.toString().indexOf(':') == -1) {
239				throw new IllegalStateException("File extension is not known to any PropertySourceLoader. "
240						+ "If the location is meant to reference a directory, it must end in '/' or File.separator");
241			}
242			throw new IllegalStateException(
243					"Incorrect ConfigDataLocationResolver chosen or file extension is not known to any PropertySourceLoader. "
244							+ "If the location is meant to reference a directory, it must end in '/' or File.separator. "
245							+ "The location is being resolved using the StandardConfigDataLocationResolver, "
246							+ "check the location prefix if a different resolver is expected");
247		}
