40	/**
41	 * {@link PropertySource} that returns a random value for any property that starts with
42	 * {@literal "random."}. Where the "unqualified property name" is the portion of the
43	 * requested property name beyond the "random." prefix, this {@link PropertySource}
44	 * returns:
45	 * <ul>
46	 * <li>When {@literal "int"}, a random {@link Integer} value, restricted by an optionally
47	 * specified range.</li>
48	 * <li>When {@literal "long"}, a random {@link Long} value, restricted by an optionally
49	 * specified range.</li>
50	 * <li>When {@literal "uuid"}, a random {@link UUID} value.</li>
51	 * <li>Otherwise, a {@code byte[]}.</li>
52	 * </ul>
53	 * The {@literal "random.int"} and {@literal "random.long"} properties supports a range
54	 * suffix whose syntax is:
55	 * <p>
56	 * {@code OPEN value (,max) CLOSE} where the {@code OPEN,CLOSE} are any character and
57	 * {@code value,max} are integers. If {@code max} is not provided, then 0 is used as the
58	 * lower bound and {@code value} is the upper bound. If {@code max} is provided then
59	 * {@code value} is the minimum value and {@code max} is the maximum (exclusive).
60	 *
61	 * @author Dave Syer
62	 * @author Matt Benson
63	 * @author Madhura Bhave
64	 * @author Moritz Halbritter
65	 * @since 1.0.0
66	 */
67	public class RandomValuePropertySource extends PropertySource<Random> {
68	
69		/**
70		 * Name of the random {@link PropertySource}.
71		 */
72		public static final String RANDOM_PROPERTY_SOURCE_NAME = "random";
73	
74		private static final String PREFIX = "random.";
75	
76		private static final Log logger = LogFactory.getLog(RandomValuePropertySource.class);
77	
78		public RandomValuePropertySource() {
79			this(RANDOM_PROPERTY_SOURCE_NAME);
80		}
81	
82		public RandomValuePropertySource(String name) {
83			super(name, new SecureRandom());
84		}
85	
86		@Override
87		public @Nullable Object getProperty(String name) {
88			if (!name.startsWith(PREFIX)) {
89				return null;
90			}
91			logger.trace(LogMessage.format("Generating random property for '%s'", name));
92			return getRandomValue(name.substring(PREFIX.length()));
93		}
94	
95		private Object getRandomValue(String type) {
96			if (type.equals("int")) {
97				return getSource().nextInt();
98			}
99			if (type.equals("long")) {
100				return getSource().nextLong();
101			}
102			String range = getRange(type, "int");
103			if (range != null) {
104				return getNextIntInRange(Range.of(range, Integer::parseInt));
105			}
106			range = getRange(type, "long");
107			if (range != null) {
108				return getNextLongInRange(Range.of(range, Long::parseLong));
109			}
110			if (type.equals("uuid")) {
111				return UUID.randomUUID().toString();
112			}
113			return getRandomBytes();
114		}
115	
116		private @Nullable String getRange(String type, String prefix) {
117			if (type.startsWith(prefix)) {
118				int startIndex = prefix.length() + 1;
119				if (type.length() > startIndex) {
120					return type.substring(startIndex, type.length() - 1);
121				}
122			}
123			return null;
124		}
125	
126		private int getNextIntInRange(Range<Integer> range) {
127			OptionalInt first = getSource().ints(1, range.getMin(), range.getMax()).findFirst();
128			assertPresent(first.isPresent(), range);
129			return first.getAsInt();
130		}
131	
132		private long getNextLongInRange(Range<Long> range) {
133			OptionalLong first = getSource().longs(1, range.getMin(), range.getMax()).findFirst();
134			assertPresent(first.isPresent(), range);
135			return first.getAsLong();
136		}
137	
138		private void assertPresent(boolean present, Range<?> range) {
139			Assert.state(present, () -> "Could not get random number for range '" + range + "'");
140		}
141	
142		private Object getRandomBytes() {
143			byte[] bytes = new byte[16];
144			getSource().nextBytes(bytes);
145			return HexFormat.of().withLowerCase().formatHex(bytes);
146		}
