61	/**
62	 * An opinionated {@link WebApplicationInitializer} to run a {@link SpringApplication}
63	 * from a traditional WAR deployment. Binds {@link Servlet}, {@link Filter} and
64	 * {@link ServletContextInitializer} beans from the application context to the server.
65	 * <p>
66	 * To configure the application either override the
67	 * {@link #configure(SpringApplicationBuilder)} method (calling
68	 * {@link SpringApplicationBuilder#sources(Class...)}) or make the initializer itself a
69	 * {@code @Configuration}. If you are using {@link SpringBootServletInitializer} in
70	 * combination with other {@link WebApplicationInitializer WebApplicationInitializers} you
71	 * might also want to add an {@code @Ordered} annotation to configure a specific startup
72	 * order.
73	 * <p>
74	 * Note that a WebApplicationInitializer is only needed if you are building a war file and
75	 * deploying it. If you prefer to run an embedded web server then you won't need this at
76	 * all.
77	 *
78	 * @author Dave Syer
79	 * @author Phillip Webb
80	 * @author Andy Wilkinson
81	 * @author Brian Clozel
82	 * @since 2.0.0
83	 * @see #configure(SpringApplicationBuilder)
84	 */
85	public abstract class SpringBootServletInitializer implements WebApplicationInitializer {
86	
87		private static final boolean REACTOR_PRESENT = ClassUtils.isPresent("reactor.core.scheduler.Schedulers",
88				SpringBootServletInitializer.class.getClassLoader());
89	
90		protected @Nullable Log logger; // Don't initialize early
91	
92		private boolean registerErrorPageFilter = true;
93	
94		/**
95		 * Set if the {@link ErrorPageFilter} should be registered. Set to {@code false} if
96		 * error page mappings should be handled through the server and not Spring Boot.
97		 * @param registerErrorPageFilter if the {@link ErrorPageFilter} should be registered.
98		 */
99		protected final void setRegisterErrorPageFilter(boolean registerErrorPageFilter) {
100			this.registerErrorPageFilter = registerErrorPageFilter;
101		}
102	
103		@Override
104		public void onStartup(ServletContext servletContext) throws ServletException {
105			servletContext.setAttribute(LoggingApplicationListener.REGISTER_SHUTDOWN_HOOK_PROPERTY, false);
106			// Logger initialization is deferred in case an ordered
107			// LogServletContextInitializer is being used
108			this.logger = LogFactory.getLog(getClass());
109			WebApplicationContext rootApplicationContext = createRootApplicationContext(servletContext);
110			if (rootApplicationContext != null) {
111				servletContext.addListener(new SpringBootContextLoaderListener(rootApplicationContext, servletContext));
112			}
113			else {
114				this.logger.debug("No ContextLoaderListener registered, as createRootApplicationContext() did not "
115						+ "return an application context");
116			}
117		}
118	
119		/**
120		 * Deregisters the JDBC drivers that were registered by the application represented by
121		 * the given {@code servletContext}. The default implementation
122		 * {@link DriverManager#deregisterDriver(Driver) deregisters} every {@link Driver}
123		 * that was loaded by the {@link ServletContext#getClassLoader web application's class
124		 * loader}.
125		 * @param servletContext the web application's servlet context
126		 * @since 2.3.0
127		 */
128		protected void deregisterJdbcDrivers(ServletContext servletContext) {
129			for (Driver driver : Collections.list(DriverManager.getDrivers())) {
130				if (driver.getClass().getClassLoader() == servletContext.getClassLoader()) {
131					try {
132						DriverManager.deregisterDriver(driver);
133					}
134					catch (SQLException ex) {
135						// Continue
136					}
137				}
138			}
139		}
140	
141		/**
142		 * Shuts down the reactor {@link Schedulers} that were initialized by
143		 * {@code Schedulers.boundedElastic()} (or similar). The default implementation
144		 * {@link Schedulers#shutdownNow()} schedulers if they were initialized on this web
145		 * application's class loader.
146		 * @param servletContext the web application's servlet context
147		 * @since 3.4.0
148		 */
149		protected void shutDownSharedReactorSchedulers(ServletContext servletContext) {
150			if (Schedulers.class.getClassLoader() == servletContext.getClassLoader()) {
151				Schedulers.shutdownNow();
152			}
153		}
154	
155		protected @Nullable WebApplicationContext createRootApplicationContext(ServletContext servletContext) {
156			SpringApplicationBuilder builder = createSpringApplicationBuilder();
157			builder.main(getClass());
158			ApplicationContext parent = getExistingRootWebApplicationContext(servletContext);
159			if (parent != null) {
160				getLogger().info("Root context already created (using as parent).");
161				servletContext.setAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE, null);
162				builder.initializers(new ParentContextApplicationContextInitializer(parent));
163			}
164			builder.initializers(new ServletContextApplicationContextInitializer(servletContext));
165			builder.contextFactory(new WarDeploymentApplicationContextFactory(servletContext));
166			builder = configure(builder);
167			builder.listeners(new WebEnvironmentPropertySourceInitializer(servletContext));
168			SpringApplication application = builder.build();
169			if (application.getAllSources().isEmpty()
170					&& MergedAnnotations.from(getClass(), SearchStrategy.TYPE_HIERARCHY).isPresent(Configuration.class)) {
171				application.addPrimarySources(Collections.singleton(getClass()));
172			}
173			Assert.state(!application.getAllSources().isEmpty(),
174					"No SpringApplication sources have been defined. Either override the "
175							+ "configure method or add an @Configuration annotation");
176			// Ensure error pages are registered
177			if (this.registerErrorPageFilter) {
178				application.addPrimarySources(Collections.singleton(ErrorPageFilterConfiguration.class));
179			}
180			application.setRegisterShutdownHook(false);
181			return run(application);
182		}
183	
184		private Log getLogger() {
185			Assert.state(this.logger != null, "Logger not set");
186			return this.logger;
187		}
188	
189		/**
190		 * Returns the {@code SpringApplicationBuilder} that is used to configure and create
191		 * the {@link SpringApplication}. The default implementation returns a new
192		 * {@code SpringApplicationBuilder} in its default state.
193		 * @return the {@code SpringApplicationBuilder}.
194		 */
195		protected SpringApplicationBuilder createSpringApplicationBuilder() {
196			return new SpringApplicationBuilder();
197		}
198	
199		/**
200		 * Called to run a fully configured {@link SpringApplication}.
201		 * @param application the application to run
202		 * @return the {@link WebApplicationContext}
203		 */
204		protected @Nullable WebApplicationContext run(SpringApplication application) {
205			return (WebApplicationContext) application.run();
206		}
207	
208		private @Nullable ApplicationContext getExistingRootWebApplicationContext(ServletContext servletContext) {
209			Object context = servletContext.getAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE);
210			if (context instanceof ApplicationContext applicationContext) {
211				return applicationContext;
212			}
213			return null;
214		}
215	
216		/**
217		 * Configure the application. Normally all you would need to do is to add sources
218		 * (e.g. config classes) because other settings have sensible defaults. You might
219		 * choose (for instance) to add default command line arguments, or set an active
220		 * Spring profile.
221		 * @param builder a builder for the application context
222		 * @return the application builder
223		 * @see SpringApplicationBuilder
224		 */
225		protected SpringApplicationBuilder configure(SpringApplicationBuilder builder) {
226			return builder;
227		}
228	
229		/**
230		 * {@link ApplicationListener} to trigger
231		 * {@link ConfigurableWebEnvironment#initPropertySources(ServletContext, jakarta.servlet.ServletConfig)}.
232		 */
233		private static final class WebEnvironmentPropertySourceInitializer
234				implements ApplicationListener<ApplicationEnvironmentPreparedEvent>, Ordered {
235	
236			private final ServletContext servletContext;
237	
238			private WebEnvironmentPropertySourceInitializer(ServletContext servletContext) {
239				this.servletContext = servletContext;
240			}
241	
242			@Override
243			public void onApplicationEvent(ApplicationEnvironmentPreparedEvent event) {
244				ConfigurableEnvironment environment = event.getEnvironment();
245				if (environment instanceof ConfigurableWebEnvironment configurableWebEnvironment) {
246					configurableWebEnvironment.initPropertySources(this.servletContext, null);
247				}
248			}
249	
250			@Override
251			public int getOrder() {
252				return Ordered.HIGHEST_PRECEDENCE;
253			}
254	
255		}
256	
257		/**
258		 * {@link ContextLoaderListener} for the initialized context.
259		 */
260		private class SpringBootContextLoaderListener extends ContextLoaderListener {
261	
262			private final ServletContext servletContext;
263	
264			SpringBootContextLoaderListener(WebApplicationContext applicationContext, ServletContext servletContext) {
265				super(applicationContext);
266				this.servletContext = servletContext;
267			}
268	
269			@Override
270			public void contextInitialized(ServletContextEvent event) {
271				// no-op because the application context is already initialized
272			}
273	
274			@Override
275			public void contextDestroyed(ServletContextEvent event) {
276				try {
277					super.contextDestroyed(event);
278				}
279				finally {
280					// Use original context so that the classloader can be accessed
281					deregisterJdbcDrivers(this.servletContext);
282					// Shut down shared reactor schedulers tied to this classloader
283					if (REACTOR_PRESENT) {
284						shutDownSharedReactorSchedulers(this.servletContext);
285					}
286				}
287			}
288	
289		}
290	
291		private static final class WarDeploymentApplicationContextFactory implements ApplicationContextFactory {
292	
293			private final ServletContext servletContext;
294	
295			private WarDeploymentApplicationContextFactory(ServletContext servletContext) {
296				this.servletContext = servletContext;
297			}
298	
299			@Override
300			public @Nullable Class<? extends ConfigurableEnvironment> getEnvironmentType(
301					@Nullable WebApplicationType webApplicationType) {
302				return (webApplicationType != WebApplicationType.SERVLET) ? null : ApplicationServletEnvironment.class;
303			}
304	
305			@Override
306			public ConfigurableEnvironment createEnvironment(@Nullable WebApplicationType webApplicationType) {
307				return new ApplicationServletEnvironment();
308			}
309	
310			@Override
311			public ConfigurableApplicationContext create(@Nullable WebApplicationType webApplicationType) {
312				return new AnnotationConfigServletWebApplicationContext() {
313	
314					@Override
315					protected void onRefresh() {
316						super.onRefresh();
317						try {
318							new WebApplicationContextInitializer(this)
319								.initialize(WarDeploymentApplicationContextFactory.this.servletContext);
320						}
321						catch (ServletException ex) {
322							throw new ApplicationContextException("Cannot initialize servlet context", ex);
323						}
324					}
325	
326				};
327			}
328	
329		}
