176		 */
177		@Override
178		public final void register(Class<?>... annotatedClasses) {
179			Assert.notEmpty(annotatedClasses, "'annotatedClasses' must not be empty");
180			this.annotatedClasses.addAll(Arrays.asList(annotatedClasses));
181		}
182	
183		/**
184		 * Perform a scan within the specified base packages. Note that {@link #refresh()}
185		 * must be called in order for the context to fully process the new class.
186		 * @param basePackages the packages to check for annotated classes
187		 * @see #register(Class...)
188		 * @see #refresh()
189		 */
190		@Override
191		public final void scan(String... basePackages) {
192			Assert.notEmpty(basePackages, "'basePackages' must not be empty");
193			this.basePackages = basePackages;
194		}
195	
196		@Override
197		protected void prepareRefresh() {
198			this.scanner.clearCache();
199			super.prepareRefresh();
200		}
201	
202		@Override
203		protected void postProcessBeanFactory(ConfigurableListableBeanFactory beanFactory) {
204			super.postProcessBeanFactory(beanFactory);
205			if (!ObjectUtils.isEmpty(this.basePackages)) {
206				this.scanner.scan(this.basePackages);
207			}
208			if (!this.annotatedClasses.isEmpty()) {
209				this.reader.register(ClassUtils.toClassArray(this.annotatedClasses));
210			}
211		}
212	
213		@Override
214		public <T> void registerBean(@Nullable String beanName, Class<T> beanClass, @Nullable Supplier<T> supplier,
215				BeanDefinitionCustomizer... customizers) {
216			this.reader.registerBean(beanClass, beanName, supplier, customizers);
217		}
218	
219	}
