17	package org.springframework.boot.web.context.servlet;
18	
19	import jakarta.servlet.ServletContext;
20	import jakarta.servlet.ServletException;
21	import org.apache.commons.logging.Log;
22	import org.apache.commons.logging.LogFactory;
23	
24	import org.springframework.beans.factory.config.ConfigurableListableBeanFactory;
25	import org.springframework.boot.web.servlet.ServletContextInitializer;
26	import org.springframework.boot.web.servlet.ServletContextInitializerBeans;
27	import org.springframework.web.context.ConfigurableWebApplicationContext;
28	import org.springframework.web.context.WebApplicationContext;
29	import org.springframework.web.context.support.ServletContextScope;
30	import org.springframework.web.context.support.WebApplicationContextUtils;
31	
32	/**
33	 * Common initialization logic for Servlet web applications.
34	 *
35	 * @author Andy Wilkinson
36	 * @since 4.0.0
37	 */
38	public class WebApplicationContextInitializer {
39	
40		private static final Log logger = LogFactory.getLog(WebApplicationContextInitializer.class);
41	
42		private final ConfigurableWebApplicationContext context;
43	
44		public WebApplicationContextInitializer(ConfigurableWebApplicationContext context) {
45			this.context = context;
46		}
47	
48		public void initialize(ServletContext servletContext) throws ServletException {
49			prepareWebApplicationContext(servletContext);
50			registerApplicationScope(servletContext, this.context.getBeanFactory());
51			WebApplicationContextUtils.registerEnvironmentBeans(this.context.getBeanFactory(), servletContext);
52			for (ServletContextInitializer initializerBean : new ServletContextInitializerBeans(
53					this.context.getBeanFactory())) {
54				initializerBean.onStartup(servletContext);
55			}
56		}
57	
58		private void prepareWebApplicationContext(ServletContext servletContext) {
59			Object rootContext = servletContext.getAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE);
60			if (rootContext != null) {
61				if (rootContext == this) {
62					throw new IllegalStateException(
63							"Cannot initialize context because there is already a root application context present - "
64									+ "check whether you have multiple ServletContextInitializers!");
65				}
66				return;
67			}
68			try {
69				servletContext.setAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE, this.context);
70				if (logger.isDebugEnabled()) {
71					logger.debug("Published root WebApplicationContext as ServletContext attribute with name ["
72							+ WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE + "]");
73				}
74				this.context.setServletContext(servletContext);
75				if (logger.isInfoEnabled()) {
76					long elapsedTime = System.currentTimeMillis() - this.context.getStartupDate();
77					logger.info("Root WebApplicationContext: initialization completed in " + elapsedTime + " ms");
78				}
79			}
80			catch (RuntimeException | Error ex) {
81				logger.error("Context initialization failed", ex);
82				servletContext.setAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE, ex);
83				throw ex;
84			}
85		}
86	
87		private void registerApplicationScope(ServletContext servletContext, ConfigurableListableBeanFactory beanFactory) {
88			ServletContextScope appScope = new ServletContextScope(servletContext);
89			beanFactory.registerScope(WebApplicationContext.SCOPE_APPLICATION, appScope);
90			// Register as ServletContext attribute, for ContextCleanupListener to detect it.
91			servletContext.setAttribute(ServletContextScope.class.getName(), appScope);
92		}
93	
94	}
