34	
35	import jakarta.servlet.Filter;
36	import jakarta.servlet.MultipartConfigElement;
37	import jakarta.servlet.Servlet;
38	import jakarta.servlet.annotation.WebInitParam;
39	import org.apache.commons.logging.Log;
40	import org.apache.commons.logging.LogFactory;
41	import org.jspecify.annotations.Nullable;
42	
43	import org.springframework.aop.scope.ScopedProxyUtils;
44	import org.springframework.beans.factory.ListableBeanFactory;
45	import org.springframework.beans.factory.support.BeanDefinitionRegistry;
46	import org.springframework.core.Ordered;
47	import org.springframework.core.annotation.AnnotationAwareOrderComparator;
48	import org.springframework.core.annotation.Order;
49	import org.springframework.util.Assert;
50	import org.springframework.util.LinkedMultiValueMap;
51	import org.springframework.util.MultiValueMap;
52	import org.springframework.util.StringUtils;
53	
54	/**
55	 * A collection {@link ServletContextInitializer}s obtained from a
56	 * {@link ListableBeanFactory}. Includes all {@link ServletContextInitializer} beans and
57	 * also adapts {@link Servlet}, {@link Filter} and certain {@link EventListener} beans.
58	 * <p>
59	 * Items are sorted so that adapted beans are top ({@link Servlet}, {@link Filter} then
60	 * {@link EventListener}) and direct {@link ServletContextInitializer} beans are at the
61	 * end. Further sorting is applied within these groups using the
62	 * {@link AnnotationAwareOrderComparator}.
63	 *
64	 * @author Dave Syer
65	 * @author Phillip Webb
66	 * @author Brian Clozel
67	 * @author Moritz Halbritter
68	 * @author Daeho Kwon
69	 * @author Dmytro Danilenkov
70	 * @since 1.4.0
71	 */
72	public class ServletContextInitializerBeans extends AbstractCollection<ServletContextInitializer> {
73	
74		private static final String DISPATCHER_SERVLET_NAME = "dispatcherServlet";
75	
76		private static final Log logger = LogFactory.getLog(ServletContextInitializerBeans.class);
77	
78		/**
79		 * Seen bean instances or bean names.
80		 */
81		private final Seen seen = new Seen();
82	
83		private final MultiValueMap<Class<?>, ServletContextInitializer> initializers;
84	
85		private final List<Class<? extends ServletContextInitializer>> initializerTypes;
86	
87		private final List<ServletContextInitializer> sortedList;
88	
89		@SafeVarargs
90		@SuppressWarnings("varargs")
91		public ServletContextInitializerBeans(ListableBeanFactory beanFactory,
92				Class<? extends ServletContextInitializer>... initializerTypes) {
93			this.initializers = new LinkedMultiValueMap<>();
94			this.initializerTypes = (initializerTypes.length != 0) ? Arrays.asList(initializerTypes)
95					: Collections.singletonList(ServletContextInitializer.class);
96			addServletContextInitializerBeans(beanFactory);
97			addAdaptableBeans(beanFactory);
98			this.sortedList = this.initializers.values()
99				.stream()
100				.flatMap((value) -> value.stream().sorted(AnnotationAwareOrderComparator.INSTANCE))
101				.toList();
102			logMappings(this.initializers);
103		}
104	
105		private void addServletContextInitializerBeans(ListableBeanFactory beanFactory) {
106			for (Class<? extends ServletContextInitializer> initializerType : this.initializerTypes) {
107				for (Entry<String, ? extends ServletContextInitializer> initializerBean : getOrderedBeansOfType(beanFactory,
108						initializerType)) {
109					addServletContextInitializerBean(initializerBean.getKey(), initializerBean.getValue(), beanFactory);
110				}
111			}
112		}
113	
114		private void addServletContextInitializerBean(String beanName, ServletContextInitializer initializer,
115				ListableBeanFactory beanFactory) {
116			if (initializer instanceof ServletRegistrationBean<?> servletRegistrationBean) {
117				Servlet source = servletRegistrationBean.getServlet();
118				addServletContextInitializerBean(Servlet.class, beanName, servletRegistrationBean, beanFactory, source);
119			}
120			else if (initializer instanceof FilterRegistrationBean<?> filterRegistrationBean) {
121				Filter source = filterRegistrationBean.getFilter();
122				addServletContextInitializerBean(Filter.class, beanName, filterRegistrationBean, beanFactory, source);
123			}
124			else if (initializer instanceof DelegatingFilterProxyRegistrationBean registrationBean) {
125				String source = registrationBean.getTargetBeanName();
126				addServletContextInitializerBean(Filter.class, beanName, registrationBean, beanFactory, source);
127			}
128			else if (initializer instanceof ServletListenerRegistrationBean<?> registrationBean) {
129				EventListener source = registrationBean.getListener();
130				addServletContextInitializerBean(EventListener.class, beanName, registrationBean, beanFactory, source);
131			}
132			else {
133				addServletContextInitializerBean(ServletContextInitializer.class, beanName, initializer, beanFactory,
134						initializer);
135			}
136		}
137	
138		private void addServletContextInitializerBean(Class<?> type, String beanName, ServletContextInitializer initializer,
139				ListableBeanFactory beanFactory, @Nullable Object source) {
140			this.initializers.add(type, initializer);
141			if (source != null) {
142				// Mark the underlying source as seen in case it wraps an existing bean
143				this.seen.add(type, source);
144			}
145			if (logger.isTraceEnabled()) {
146				String resourceDescription = getResourceDescription(beanName, beanFactory);
147				int order = getOrder(initializer);
148				logger.trace("Added existing " + type.getSimpleName() + " initializer bean '" + beanName + "'; order="
149						+ order + ", resource=" + resourceDescription);
150			}
151		}
152	
153		private @Nullable String getResourceDescription(String beanName, ListableBeanFactory beanFactory) {
154			if (beanFactory instanceof BeanDefinitionRegistry registry) {
155				return registry.getBeanDefinition(beanName).getResourceDescription();
156			}
157			return "unknown";
158		}
159	
160		@SuppressWarnings("unchecked")
161		protected void addAdaptableBeans(ListableBeanFactory beanFactory) {
162			MultipartConfigElement multipartConfig = getMultipartConfig(beanFactory);
163			addAsRegistrationBean(beanFactory, Servlet.class,
164					new ServletRegistrationBeanAdapter(multipartConfig, beanFactory));
165			addAsRegistrationBean(beanFactory, Filter.class, new FilterRegistrationBeanAdapter(beanFactory));
166			for (Class<?> listenerType : ServletListenerRegistrationBean.getSupportedTypes()) {
167				addAsRegistrationBean(beanFactory, EventListener.class, (Class<EventListener>) listenerType,
168						new ServletListenerRegistrationBeanAdapter());
169			}
170		}
171	
172		private @Nullable MultipartConfigElement getMultipartConfig(ListableBeanFactory beanFactory) {
173			List<Entry<String, MultipartConfigElement>> beans = getOrderedBeansOfType(beanFactory,
174					MultipartConfigElement.class);
175			return beans.isEmpty() ? null : beans.get(0).getValue();
176		}
177	
178		protected <T> void addAsRegistrationBean(ListableBeanFactory beanFactory, Class<T> type,
179				RegistrationBeanAdapter<T> adapter) {
180			addAsRegistrationBean(beanFactory, type, type, adapter);
181		}
182	
183		private <T, B extends T> void addAsRegistrationBean(ListableBeanFactory beanFactory, Class<T> type,
184				Class<B> beanType, RegistrationBeanAdapter<T> adapter) {
185			List<Map.Entry<String, B>> entries = getOrderedBeansOfType(beanFactory, beanType, this.seen);
186			for (Entry<String, B> entry : entries) {
187				String beanName = entry.getKey();
188				B bean = entry.getValue();
189				if (this.seen.add(type, bean)) {
190					// One that we haven't already seen
191					RegistrationBean registration = adapter.createRegistrationBean(beanName, bean, entries.size());
192					Integer order = findOrder(bean);
193					if (order != null) {
194						registration.setOrder(order);
195					}
196					this.initializers.add(type, registration);
197					if (logger.isTraceEnabled()) {
198						logger.trace("Created " + type.getSimpleName() + " initializer for bean '" + beanName + "'; order="
199								+ order + ", resource=" + getResourceDescription(beanName, beanFactory));
200					}
201				}
202			}
203		}
204	
205		private int getOrder(Object value) {
206			Integer order = findOrder(value);
207			return (order != null) ? order : Ordered.LOWEST_PRECEDENCE;
208		}
209	
210		private @Nullable Integer findOrder(Object value) {
211			return new AnnotationAwareOrderComparator() {
212	
213				@Override
214				public @Nullable Integer findOrder(Object obj) {
215					return super.findOrder(obj);
216				}
217	
218			}.findOrder(value);
219		}
220	
221		private <T> List<Entry<String, T>> getOrderedBeansOfType(ListableBeanFactory beanFactory, Class<T> type) {
222			return getOrderedBeansOfType(beanFactory, type, Seen.empty());
223		}
224	
225		private <T> List<Entry<String, T>> getOrderedBeansOfType(ListableBeanFactory beanFactory, Class<T> type,
226				Seen seen) {
227			String[] names = beanFactory.getBeanNamesForType(type, true, false);
228			Map<String, T> map = new LinkedHashMap<>();
229			for (String name : names) {
230				if (!seen.contains(type, name) && !ScopedProxyUtils.isScopedTarget(name)) {
231					T bean = beanFactory.getBean(name, type);
232					if (!seen.contains(type, bean)) {
233						map.put(name, bean);
234					}
235				}
236			}
237			List<Entry<String, T>> beans = new ArrayList<>(map.entrySet());
238			beans.sort((o1, o2) -> AnnotationAwareOrderComparator.INSTANCE.compare(o1.getValue(), o2.getValue()));
239			return beans;
240		}
241	
242		private void logMappings(MultiValueMap<Class<?>, ServletContextInitializer> initializers) {
243			if (logger.isDebugEnabled()) {
244				logMappings("filters", initializers, Filter.class, FilterRegistrationBean.class);
245				logMappings("servlets", initializers, Servlet.class, ServletRegistrationBean.class);
246			}
247		}
248	
249		private void logMappings(String name, MultiValueMap<Class<?>, ServletContextInitializer> initializers,
250				Class<?> type, Class<? extends RegistrationBean> registrationType) {
251			List<ServletContextInitializer> registrations = new ArrayList<>();
252			registrations.addAll(initializers.getOrDefault(registrationType, Collections.emptyList()));
253			registrations.addAll(initializers.getOrDefault(type, Collections.emptyList()));
254			String info = registrations.stream().map(Object::toString).collect(Collectors.joining(", "));
255			logger.debug("Mapping " + name + ": " + info);
256		}
257	
258		@Override
259		public Iterator<ServletContextInitializer> iterator() {
260			return this.sortedList.iterator();
261		}
262	
263		@Override
264		public int size() {
265			return this.sortedList.size();
266		}
267	
268		/**
269		 * Adapter to convert a given Bean type into a {@link RegistrationBean} (and hence a
270		 * {@link ServletContextInitializer}).
271		 *
272		 * @param <T> the type of the Bean to adapt
273		 */
274		@FunctionalInterface
275		protected interface RegistrationBeanAdapter<T> {
276	
277			RegistrationBean createRegistrationBean(String beanName, T source, int totalNumberOfSourceBeans);
278	
279		}
280	
281		/**
282		 * {@link RegistrationBeanAdapter} for {@link Servlet} beans.
283		 */
284		private static class ServletRegistrationBeanAdapter implements RegistrationBeanAdapter<Servlet> {
285	
286			private final @Nullable MultipartConfigElement multipartConfig;
287	
288			private final ListableBeanFactory beanFactory;
289	
290			ServletRegistrationBeanAdapter(@Nullable MultipartConfigElement multipartConfig,
291					ListableBeanFactory beanFactory) {
292				this.multipartConfig = multipartConfig;
293				this.beanFactory = beanFactory;
294			}
295	
296			@Override
297			public RegistrationBean createRegistrationBean(String beanName, Servlet source, int totalNumberOfSourceBeans) {
298				String url = (totalNumberOfSourceBeans != 1) ? "/" + beanName + "/" : "/";
299				if (beanName.equals(DISPATCHER_SERVLET_NAME)) {
300					url = "/"; // always map the main dispatcherServlet to "/"
301				}
302				ServletRegistrationBean<Servlet> bean = new ServletRegistrationBean<>(source, url);
303				bean.setName(beanName);
304				bean.setMultipartConfig(this.multipartConfig);
305				ServletRegistration registrationAnnotation = this.beanFactory.findAnnotationOnBean(beanName,
306						ServletRegistration.class);
307				if (registrationAnnotation != null) {
308					Order orderAnnotation = this.beanFactory.findAnnotationOnBean(beanName, Order.class);
309					Assert.notNull(orderAnnotation, "'orderAnnotation' must not be null");
310					configureFromAnnotation(bean, registrationAnnotation, orderAnnotation);
311				}
312				return bean;
313			}
314	
315			private void configureFromAnnotation(ServletRegistrationBean<Servlet> bean, ServletRegistration registration,
316					Order order) {
317				bean.setEnabled(registration.enabled());
318				bean.setOrder(order.value());
319				if (StringUtils.hasText(registration.name())) {
320					bean.setName(registration.name());
321				}
322				bean.setAsyncSupported(registration.asyncSupported());
323				bean.setIgnoreRegistrationFailure(registration.ignoreRegistrationFailure());
324				bean.setLoadOnStartup(registration.loadOnStartup());
325				bean.setUrlMappings(Arrays.asList(registration.urlMappings()));
326				for (WebInitParam param : registration.initParameters()) {
327					bean.addInitParameter(param.name(), param.value());
328				}
329				bean.setMultipartConfig(new MultipartConfigElement(registration.multipartConfig()));
330			}
331	
332		}
333	
334		/**
335		 * {@link RegistrationBeanAdapter} implementation for {@link Filter} beans.
336		 * <p>
337		 * <b>NOTE:</b> A similar implementation is used in
338		 * {@code SpringBootMockMvcBuilderCustomizer} for registering
339		 * {@code @FilterRegistration} beans with {@code @MockMvc}. If you modify this class,
340		 * please also update {@code SpringBootMockMvcBuilderCustomizer} if needed.
341		 * </p>
342		 */
343		private static class FilterRegistrationBeanAdapter implements RegistrationBeanAdapter<Filter> {
344	
345			private final ListableBeanFactory beanFactory;
346	
347			FilterRegistrationBeanAdapter(ListableBeanFactory beanFactory) {
348				this.beanFactory = beanFactory;
349			}
350	
351			@Override
352			public RegistrationBean createRegistrationBean(String beanName, Filter source, int totalNumberOfSourceBeans) {
353				FilterRegistrationBean<Filter> bean = new FilterRegistrationBean<>(source);
354				bean.setName(beanName);
355				FilterRegistration registrationAnnotation = this.beanFactory.findAnnotationOnBean(beanName,
356						FilterRegistration.class);
357				if (registrationAnnotation != null) {
358					Order orderAnnotation = this.beanFactory.findAnnotationOnBean(beanName, Order.class);
359					Assert.notNull(orderAnnotation, "'orderAnnotation' must not be null");
360					configureFromAnnotation(bean, registrationAnnotation, orderAnnotation);
361				}
362				return bean;
363			}
364	
365			private void configureFromAnnotation(FilterRegistrationBean<Filter> bean, FilterRegistration registration,
366					Order order) {
367				bean.setEnabled(registration.enabled());
368				bean.setOrder(order.value());
369				if (StringUtils.hasText(registration.name())) {
370					bean.setName(registration.name());
371				}
372				bean.setAsyncSupported(registration.asyncSupported());
373				if (registration.dispatcherTypes().length > 0) {
374					bean.setDispatcherTypes(EnumSet.copyOf(Arrays.asList(registration.dispatcherTypes())));
375				}
376				bean.setIgnoreRegistrationFailure(registration.ignoreRegistrationFailure());
377				bean.setMatchAfter(registration.matchAfter());
378				bean.setServletNames(Arrays.asList(registration.servletNames()));
379				bean.setUrlPatterns(Arrays.asList(registration.urlPatterns()));
380				for (WebInitParam param : registration.initParameters()) {
381					bean.addInitParameter(param.name(), param.value());
382				}
383				this.beanFactory.getBeanProvider(ServletRegistrationBean.class).forEach((servletRegistrationBean) -> {
384					for (Class<?> servletClass : registration.servletClasses()) {
385						if (servletClass.isInstance(servletRegistrationBean.getServlet())) {
386							bean.addServletRegistrationBeans(servletRegistrationBean);
387						}
388					}
389				});
390			}
391	
392		}
393	
394		/**
395		 * {@link RegistrationBeanAdapter} for certain {@link EventListener} beans.
396		 */
397		private static final class ServletListenerRegistrationBeanAdapter
398				implements RegistrationBeanAdapter<EventListener> {
399	
400			@Override
401			public RegistrationBean createRegistrationBean(String beanName, EventListener source,
402					int totalNumberOfSourceBeans) {
403				return new ServletListenerRegistrationBean<>(source);
404			}
405	
406		}
407	
408		/**
409		 * Tracks seen initializers.
410		 */
411		private static final class Seen {
412	
413			private final Map<Class<?>, Set<Object>> seen = new HashMap<>();
414	
415			boolean add(Class<?> type, Object object) {
416				if (contains(type, object)) {
417					return false;
418				}
419				return this.seen.computeIfAbsent(type, (ignore) -> new HashSet<>()).add(object);
420			}
421	
422			boolean contains(Class<?> type, Object object) {
423				if (this.seen.isEmpty()) {
424					return false;
425				}
426				// If it has been directly seen, or the implemented ServletContextInitializer
427				// has been seen already
428				if (type != ServletContextInitializer.class
429						&& this.seen.getOrDefault(type, Collections.emptySet()).contains(object)) {
430					return true;
431				}
432				return this.seen.getOrDefault(ServletContextInitializer.class, Collections.emptySet()).contains(object);
433			}
434	
435			static Seen empty() {
436				return new Seen();
437			}
438	
439		}
440	
441	}
