34	/**
35	 * A {@link ServletContextInitializer} to register {@link Servlet}s in a Servlet 3.0+
36	 * container. Similar to the {@link ServletContext#addServlet(String, Servlet)
37	 * registration} features provided by {@link ServletContext} but with a Spring Bean
38	 * friendly design.
39	 * <p>
40	 * The {@link #setServlet(Servlet) servlet} must be specified before calling
41	 * {@link #onStartup}. URL mapping can be configured used {@link #setUrlMappings} or
42	 * omitted when mapping to '/*' (unless
43	 * {@link #ServletRegistrationBean(Servlet, boolean, String...) alwaysMapUrl} is set to
44	 * {@code false}). The servlet name will be deduced if not specified.
45	 *
46	 * @param <T> the type of the {@link Servlet} to register
47	 * @author Phillip Webb
48	 * @since 1.4.0
49	 * @see ServletContextInitializer
50	 * @see ServletContext#addServlet(String, Servlet)
51	 * @see org.springframework.boot.web.servlet.ServletRegistration
52	 */
53	public class ServletRegistrationBean<T extends Servlet> extends DynamicRegistrationBean<ServletRegistration.Dynamic> {
54	
55		private static final String[] DEFAULT_MAPPINGS = { "/*" };
56	
57		private @Nullable T servlet;
58	
59		private Set<String> urlMappings = new LinkedHashSet<>();
60	
61		private boolean alwaysMapUrl = true;
62	
63		private int loadOnStartup = -1;
64	
65		private @Nullable MultipartConfigElement multipartConfig;
66	
67		/**
68		 * Create a new {@link ServletRegistrationBean} instance.
69		 */
70		public ServletRegistrationBean() {
71		}
72	
73		/**
74		 * Create a new {@link ServletRegistrationBean} instance with the specified
75		 * {@link Servlet} and URL mappings.
76		 * @param servlet the servlet being mapped
77		 * @param urlMappings the URLs being mapped
78		 */
79		public ServletRegistrationBean(T servlet, String... urlMappings) {
80			this(servlet, true, urlMappings);
81		}
82	
83		/**
84		 * Create a new {@link ServletRegistrationBean} instance with the specified
85		 * {@link Servlet} and URL mappings.
86		 * @param servlet the servlet being mapped
87		 * @param alwaysMapUrl if omitted URL mappings should be replaced with '/*'
88		 * @param urlMappings the URLs being mapped
89		 */
90		public ServletRegistrationBean(T servlet, boolean alwaysMapUrl, String... urlMappings) {
91			Assert.notNull(servlet, "'servlet' must not be null");
92			Assert.notNull(urlMappings, "'urlMappings' must not be null");
93			this.servlet = servlet;
94			this.alwaysMapUrl = alwaysMapUrl;
95			this.urlMappings.addAll(Arrays.asList(urlMappings));
96		}
97	
98		/**
99		 * Sets the servlet to be registered.
100		 * @param servlet the servlet
101		 */
102		public void setServlet(T servlet) {
103			Assert.notNull(servlet, "'servlet' must not be null");
104			this.servlet = servlet;
105		}
106	
107		/**
108		 * Return the servlet being registered.
109		 * @return the servlet
110		 */
111		public @Nullable T getServlet() {
112			return this.servlet;
113		}
114	
115		/**
116		 * Set the URL mappings for the servlet. If not specified the mapping will default to
117		 * '/'. This will replace any previously specified mappings.
118		 * @param urlMappings the mappings to set
119		 * @see #addUrlMappings(String...)
120		 */
121		public void setUrlMappings(Collection<String> urlMappings) {
122			Assert.notNull(urlMappings, "'urlMappings' must not be null");
123			this.urlMappings = new LinkedHashSet<>(urlMappings);
124		}
125	
126		/**
127		 * Return a mutable collection of the URL mappings, as defined in the Servlet
128		 * specification, for the servlet.
129		 * @return the urlMappings
130		 */
131		public Collection<String> getUrlMappings() {
132			return this.urlMappings;
133		}
134	
135		/**
136		 * Add URL mappings, as defined in the Servlet specification, for the servlet.
137		 * @param urlMappings the mappings to add
138		 * @see #setUrlMappings(Collection)
139		 */
140		public void addUrlMappings(String... urlMappings) {
141			Assert.notNull(urlMappings, "'urlMappings' must not be null");
142			this.urlMappings.addAll(Arrays.asList(urlMappings));
143		}
144	
145		/**
146		 * Sets the {@code loadOnStartup} priority. See
147		 * {@link ServletRegistration.Dynamic#setLoadOnStartup} for details.
148		 * @param loadOnStartup if load on startup is enabled
149		 */
150		public void setLoadOnStartup(int loadOnStartup) {
151			this.loadOnStartup = loadOnStartup;
152		}
153	
154		/**
155		 * Set the {@link MultipartConfigElement multi-part configuration}.
156		 * @param multipartConfig the multipart configuration to set or {@code null}
157		 */
158		public void setMultipartConfig(@Nullable MultipartConfigElement multipartConfig) {
159			this.multipartConfig = multipartConfig;
160		}
161	
162		/**
163		 * Returns the {@link MultipartConfigElement multi-part configuration} to be applied
164		 * or {@code null}.
165		 * @return the multipart config
166		 */
167		public @Nullable MultipartConfigElement getMultipartConfig() {
168			return this.multipartConfig;
169		}
170	
171		@Override
172		protected String getDescription() {
173			Assert.state(this.servlet != null, "Unable to return description for null servlet");
174			return "servlet " + getServletName();
175		}
176	
177		@Override
178		protected ServletRegistration.Dynamic addRegistration(String description, ServletContext servletContext) {
179			String name = getServletName();
180			return servletContext.addServlet(name, this.servlet);
181		}
182	
183		/**
184		 * Configure registration settings. Subclasses can override this method to perform
185		 * additional configuration if required.
186		 * @param registration the registration
187		 */
188		@Override
189		protected void configure(ServletRegistration.Dynamic registration) {
190			super.configure(registration);
191			String[] urlMapping = StringUtils.toStringArray(this.urlMappings);
192			if (urlMapping.length == 0 && this.alwaysMapUrl) {
193				urlMapping = DEFAULT_MAPPINGS;
194			}
195			if (!ObjectUtils.isEmpty(urlMapping)) {
196				registration.addMapping(urlMapping);
197			}
198			registration.setLoadOnStartup(this.loadOnStartup);
199			if (this.multipartConfig != null) {
200				registration.setMultipartConfig(this.multipartConfig);
201			}
202		}
203	
204		/**
205		 * Returns the servlet name that will be registered.
206		 * @return the servlet name
207		 */
208		public String getServletName() {
209			return getOrDeduceName(this.servlet);
210		}
211	
212		@Override
213		public String toString() {
214			return getServletName() + " urls=" + getUrlMappings();
215		}
216	
217	}
