27	/**
28	 * Base class for Servlet 3.0+ based registration beans.
29	 *
30	 * @author Phillip Webb
31	 * @since 1.4.0
32	 * @see ServletRegistrationBean
33	 * @see FilterRegistrationBean
34	 * @see DelegatingFilterProxyRegistrationBean
35	 * @see ServletListenerRegistrationBean
36	 */
37	public abstract class RegistrationBean implements ServletContextInitializer, Ordered {
38	
39		private static final Log logger = LogFactory.getLog(RegistrationBean.class);
40	
41		private int order = Ordered.LOWEST_PRECEDENCE;
42	
43		private boolean enabled = true;
44	
45		@Override
46		public final void onStartup(ServletContext servletContext) throws ServletException {
47			String description = getDescription();
48			if (!isEnabled()) {
49				logger.info(StringUtils.capitalize(description) + " was not registered (disabled)");
50				return;
51			}
52			register(description, servletContext);
53		}
54	
55		/**
56		 * Return a description of the registration. For example "Servlet resourceServlet"
57		 * @return a description of the registration
58		 */
59		protected abstract String getDescription();
60	
61		/**
62		 * Register this bean with the servlet context.
63		 * @param description a description of the item being registered
64		 * @param servletContext the servlet context
65		 */
66		protected abstract void register(String description, ServletContext servletContext);
67	
68		/**
69		 * Flag to indicate that the registration is enabled.
70		 * @param enabled the enabled to set
71		 */
72		public void setEnabled(boolean enabled) {
73			this.enabled = enabled;
74		}
75	
76		/**
77		 * Return if the registration is enabled.
78		 * @return if enabled (default {@code true})
79		 */
80		public boolean isEnabled() {
81			return this.enabled;
82		}
83	
84		/**
85		 * Set the order of the registration bean.
86		 * @param order the order
87		 */
88		public void setOrder(int order) {
89			this.order = order;
90		}
91	
92		/**
93		 * Get the order of the registration bean.
94		 * @return the order
95		 */
96		@Override
97		public int getOrder() {
98			return this.order;
99		}
100	
101	}
