37	/**
38	 * A {@link ServletContextInitializer} to register {@link EventListener}s in a Servlet
39	 * 3.0+ container. Similar to the {@link ServletContext#addListener(EventListener)
40	 * registration} features provided by {@link ServletContext} but with a Spring Bean
41	 * friendly design.
42	 *
43	 * This bean can be used to register the following types of listener:
44	 * <ul>
45	 * <li>{@link ServletContextAttributeListener}</li>
46	 * <li>{@link ServletRequestListener}</li>
47	 * <li>{@link ServletRequestAttributeListener}</li>
48	 * <li>{@link HttpSessionAttributeListener}</li>
49	 * <li>{@link HttpSessionIdListener}</li>
50	 * <li>{@link HttpSessionListener}</li>
51	 * <li>{@link ServletContextListener}</li>
52	 * </ul>
53	 *
54	 * @param <T> the type of listener
55	 * @author Dave Syer
56	 * @author Phillip Webb
57	 * @since 1.4.0
58	 */
59	public class ServletListenerRegistrationBean<T extends EventListener> extends RegistrationBean {
60	
61		private static final Set<Class<?>> SUPPORTED_TYPES;
62	
63		static {
64			Set<Class<?>> types = new HashSet<>();
65			types.add(ServletContextAttributeListener.class);
66			types.add(ServletRequestListener.class);
67			types.add(ServletRequestAttributeListener.class);
68			types.add(HttpSessionAttributeListener.class);
69			types.add(HttpSessionIdListener.class);
70			types.add(HttpSessionListener.class);
71			types.add(ServletContextListener.class);
72			SUPPORTED_TYPES = Collections.unmodifiableSet(types);
73		}
74	
75		private @Nullable T listener;
76	
77		/**
78		 * Create a new {@link ServletListenerRegistrationBean} instance.
79		 */
80		public ServletListenerRegistrationBean() {
81		}
82	
83		/**
84		 * Create a new {@link ServletListenerRegistrationBean} instance.
85		 * @param listener the listener to register
86		 */
87		public ServletListenerRegistrationBean(T listener) {
88			Assert.notNull(listener, "'listener' must not be null");
89			Assert.isTrue(isSupportedType(listener), "'listener' is not of a supported type");
90			this.listener = listener;
91		}
92	
93		/**
94		 * Set the listener that will be registered.
95		 * @param listener the listener to register
96		 */
97		public void setListener(T listener) {
98			Assert.notNull(listener, "'listener' must not be null");
99			Assert.isTrue(isSupportedType(listener), "'listener' is not of a supported type");
100			this.listener = listener;
101		}
102	
103		/**
104		 * Return the listener to be registered.
105		 * @return the listener to be registered
106		 */
107		public @Nullable T getListener() {
108			return this.listener;
109		}
110	
111		@Override
112		protected String getDescription() {
113			Assert.notNull(this.listener, "'listener' must not be null");
114			return "listener " + this.listener;
115		}
116	
117		@Override
118		protected void register(String description, ServletContext servletContext) {
119			try {
120				servletContext.addListener(this.listener);
121			}
122			catch (RuntimeException ex) {
123				throw new IllegalStateException("Failed to add listener '" + this.listener + "' to servlet context", ex);
124			}
125		}
126	
127		/**
128		 * Returns {@code true} if the specified listener is one of the supported types.
129		 * @param listener the listener to test
130		 * @return if the listener is of a supported type
131		 */
132		public static boolean isSupportedType(EventListener listener) {
133			for (Class<?> type : SUPPORTED_TYPES) {
134				if (ClassUtils.isAssignableValue(type, listener)) {
135					return true;
136				}
137			}
138			return false;
139		}
140	
141		/**
142		 * Return the supported types for this registration.
143		 * @return the supported types
144		 */
145		public static Set<Class<?>> getSupportedTypes() {
146			return SUPPORTED_TYPES;
147		}
148	
149	}
