46	 * @since 1.5.22
47	 */
48	public abstract class AbstractFilterRegistrationBean<T extends Filter> extends DynamicRegistrationBean<Dynamic> {
49	
50		private static final String[] DEFAULT_URL_MAPPINGS = { "/*" };
51	
52		private Set<ServletRegistrationBean<?>> servletRegistrationBeans = new LinkedHashSet<>();
53	
54		private Set<String> servletNames = new LinkedHashSet<>();
55	
56		private Set<String> urlPatterns = new LinkedHashSet<>();
57	
58		private @Nullable EnumSet<DispatcherType> dispatcherTypes;
59	
60		private boolean matchAfter;
61	
62		/**
63		 * Create a new instance to be registered with the specified
64		 * {@link ServletRegistrationBean}s.
65		 * @param servletRegistrationBeans associate {@link ServletRegistrationBean}s
66		 */
67		AbstractFilterRegistrationBean(ServletRegistrationBean<?>... servletRegistrationBeans) {
68			Assert.notNull(servletRegistrationBeans, "'servletRegistrationBeans' must not be null");
69			Collections.addAll(this.servletRegistrationBeans, servletRegistrationBeans);
70		}
71	
72		/**
73		 * Set {@link ServletRegistrationBean}s that the filter will be registered against.
74		 * @param servletRegistrationBeans the Servlet registration beans
75		 */
76		public void setServletRegistrationBeans(Collection<? extends ServletRegistrationBean<?>> servletRegistrationBeans) {
77			Assert.notNull(servletRegistrationBeans, "'servletRegistrationBeans' must not be null");
78			this.servletRegistrationBeans = new LinkedHashSet<>(servletRegistrationBeans);
79		}
80	
81		/**
82		 * Return a mutable collection of the {@link ServletRegistrationBean} that the filter
83		 * will be registered against. {@link ServletRegistrationBean}s.
84		 * @return the Servlet registration beans
85		 * @see #setServletNames
86		 * @see #setUrlPatterns
87		 */
88		public Collection<ServletRegistrationBean<?>> getServletRegistrationBeans() {
89			return this.servletRegistrationBeans;
90		}
91	
92		/**
93		 * Add {@link ServletRegistrationBean}s for the filter.
94		 * @param servletRegistrationBeans the servlet registration beans to add
95		 * @see #setServletRegistrationBeans
96		 */
97		public void addServletRegistrationBeans(ServletRegistrationBean<?>... servletRegistrationBeans) {
98			Assert.notNull(servletRegistrationBeans, "'servletRegistrationBeans' must not be null");
99			Collections.addAll(this.servletRegistrationBeans, servletRegistrationBeans);
100		}
101	
102		/**
103		 * Set servlet names that the filter will be registered against. This will replace any
104		 * previously specified servlet names.
105		 * @param servletNames the servlet names
106		 * @see #setServletRegistrationBeans
107		 * @see #setUrlPatterns
108		 */
109		public void setServletNames(Collection<String> servletNames) {
110			Assert.notNull(servletNames, "'servletNames' must not be null");
111			this.servletNames = new LinkedHashSet<>(servletNames);
112		}
113	
114		/**
115		 * Return a mutable collection of servlet names that the filter will be registered
116		 * against.
117		 * @return the servlet names
118		 */
119		public Collection<String> getServletNames() {
120			return this.servletNames;
121		}
122	
123		/**
124		 * Add servlet names for the filter.
125		 * @param servletNames the servlet names to add
126		 */
127		public void addServletNames(String... servletNames) {
128			Assert.notNull(servletNames, "'servletNames' must not be null");
129			this.servletNames.addAll(Arrays.asList(servletNames));
130		}
131	
132		/**
133		 * Set the URL patterns that the filter will be registered against. This will replace
134		 * any previously specified URL patterns.
135		 * @param urlPatterns the URL patterns
136		 * @see #setServletRegistrationBeans
137		 * @see #setServletNames
138		 */
139		public void setUrlPatterns(Collection<String> urlPatterns) {
140			Assert.notNull(urlPatterns, "'urlPatterns' must not be null");
141			this.urlPatterns = new LinkedHashSet<>(urlPatterns);
142		}
143	
144		/**
145		 * Return a mutable collection of URL patterns, as defined in the Servlet
146		 * specification, that the filter will be registered against.
147		 * @return the URL patterns
148		 */
149		public Collection<String> getUrlPatterns() {
150			return this.urlPatterns;
151		}
152	
153		/**
154		 * Add URL patterns, as defined in the Servlet specification, that the filter will be
155		 * registered against.
156		 * @param urlPatterns the URL patterns
157		 */
158		public void addUrlPatterns(String... urlPatterns) {
159			Assert.notNull(urlPatterns, "'urlPatterns' must not be null");
160			Collections.addAll(this.urlPatterns, urlPatterns);
161		}
162	
163		/**
164		 * Determines the {@link DispatcherType dispatcher types} for which the filter should
165		 * be registered. Applies defaults based on the type of filter being registered if
166		 * none have been configured. Modifications to the returned {@link EnumSet} will have
167		 * no effect on the registration.
168		 * @return the dispatcher types, never {@code null}
169		 * @since 3.2.0
170		 */
171		public EnumSet<DispatcherType> determineDispatcherTypes() {
172			if (CollectionUtils.isEmpty(this.dispatcherTypes)) {
173				T filter = getFilter();
174				Assert.state(filter != null, "'filter' must not be null");
175				if (ClassUtils.isPresent("org.springframework.web.filter.OncePerRequestFilter",
176						filter.getClass().getClassLoader()) && filter instanceof OncePerRequestFilter) {
177					return EnumSet.allOf(DispatcherType.class);
178				}
179				else {
180					return EnumSet.of(DispatcherType.REQUEST);
181				}
182			}
183			return EnumSet.copyOf(this.dispatcherTypes);
184		}
185	
186		/**
187		 * Convenience method to {@link #setDispatcherTypes(EnumSet) set dispatcher types}
188		 * using the specified elements.
189		 * @param first the first dispatcher type
190		 * @param rest additional dispatcher types
191		 */
192		public void setDispatcherTypes(DispatcherType first, DispatcherType... rest) {
193			this.dispatcherTypes = EnumSet.of(first, rest);
194		}
195	
196		/**
197		 * Sets the dispatcher types that should be used with the registration.
198		 * @param dispatcherTypes the dispatcher types
199		 */
200		public void setDispatcherTypes(@Nullable EnumSet<DispatcherType> dispatcherTypes) {
201			this.dispatcherTypes = dispatcherTypes;
202		}
203	
204		/**
205		 * Set if the filter mappings should be matched after any declared filter mappings of
206		 * the ServletContext. Defaults to {@code false} indicating the filters are supposed
207		 * to be matched before any declared filter mappings of the ServletContext.
208		 * @param matchAfter if filter mappings are matched after
209		 */
210		public void setMatchAfter(boolean matchAfter) {
211			this.matchAfter = matchAfter;
212		}
213	
214		/**
215		 * Return if filter mappings should be matched after any declared Filter mappings of
216		 * the ServletContext.
217		 * @return if filter mappings are matched after
218		 */
219		public boolean isMatchAfter() {
220			return this.matchAfter;
221		}
222	
223		@Override
224		protected String getDescription() {
225			Filter filter = getFilter();
226			Assert.notNull(filter, "'filter' must not be null");
227			return "filter " + getOrDeduceName(filter);
228		}
229	
230		@Override
231		protected Dynamic addRegistration(String description, ServletContext servletContext) {
232			Filter filter = getFilter();
233			return servletContext.addFilter(getOrDeduceName(filter), filter);
234		}
235	
236		/**
237		 * Configure registration settings. Subclasses can override this method to perform
238		 * additional configuration if required.
239		 * @param registration the registration
240		 */
241		@Override
242		protected void configure(FilterRegistration.Dynamic registration) {
243			super.configure(registration);
244			EnumSet<DispatcherType> dispatcherTypes = determineDispatcherTypes();
245			Set<String> servletNames = new LinkedHashSet<>();
246			for (ServletRegistrationBean<?> servletRegistrationBean : this.servletRegistrationBeans) {
247				servletNames.add(servletRegistrationBean.getServletName());
248			}
249			servletNames.addAll(this.servletNames);
250			if (servletNames.isEmpty() && this.urlPatterns.isEmpty()) {
251				registration.addMappingForUrlPatterns(dispatcherTypes, this.matchAfter, DEFAULT_URL_MAPPINGS);
252			}
253			else {
254				if (!servletNames.isEmpty()) {
255					registration.addMappingForServletNames(dispatcherTypes, this.matchAfter,
256							StringUtils.toStringArray(servletNames));
257				}
258				if (!this.urlPatterns.isEmpty()) {
259					registration.addMappingForUrlPatterns(dispatcherTypes, this.matchAfter,
260							StringUtils.toStringArray(this.urlPatterns));
261				}
262			}
263		}
264	
265		/**
266		 * Return the {@link Filter} to be registered.
267		 * @return the filter
268		 */
269		public abstract @Nullable T getFilter();
270	
271		/**
272		 * Returns the filter name that will be registered.
273		 * @return the filter name
274		 * @since 3.2.0
275		 */
276		public String getFilterName() {
277			return getOrDeduceName(getFilter());
278		}
279	
280		@Override
281		public String toString() {
282			StringBuilder builder = new StringBuilder(getOrDeduceName(this));
283			if (this.servletNames.isEmpty() && this.urlPatterns.isEmpty()) {
284				builder.append(" urls=").append(Arrays.toString(DEFAULT_URL_MAPPINGS));
285			}
286			else {
287				if (!this.servletNames.isEmpty()) {
288					builder.append(" servlets=").append(this.servletNames);
289				}
290				if (!this.urlPatterns.isEmpty()) {
291					builder.append(" urls=").append(this.urlPatterns);
292				}
293			}
294			builder.append(" order=").append(getOrder());
295			return builder.toString();
296		}
297	
298	}
