17	package org.springframework.boot.web.servlet;
18	
19	import java.util.LinkedHashMap;
20	import java.util.Map;
21	
22	import jakarta.servlet.Registration;
23	import jakarta.servlet.ServletContext;
24	import org.apache.commons.logging.Log;
25	import org.apache.commons.logging.LogFactory;
26	import org.jspecify.annotations.Nullable;
27	
28	import org.springframework.beans.factory.BeanNameAware;
29	import org.springframework.core.Conventions;
30	import org.springframework.util.Assert;
31	import org.springframework.util.StringUtils;
32	
33	/**
34	 * Base class for Servlet 3.0+ {@link jakarta.servlet.Registration.Dynamic dynamic} based
35	 * registration beans.
36	 *
37	 * @param <D> the dynamic registration result
38	 * @author Phillip Webb
39	 * @author Moritz Halbritter
40	 * @since 2.0.0
41	 */
42	public abstract class DynamicRegistrationBean<D extends Registration.Dynamic> extends RegistrationBean
43			implements BeanNameAware {
44	
45		private static final Log logger = LogFactory.getLog(RegistrationBean.class);
46	
47		private @Nullable String name;
48	
49		private boolean asyncSupported = true;
50	
51		private Map<String, String> initParameters = new LinkedHashMap<>();
52	
53		private @Nullable String beanName;
54	
55		private boolean ignoreRegistrationFailure;
56	
57		/**
58		 * Set the name of this registration. If not specified the bean name will be used.
59		 * @param name the name of the registration
60		 */
61		public void setName(String name) {
62			Assert.hasLength(name, "'name' must not be empty");
63			this.name = name;
64		}
65	
66		/**
67		 * Sets if asynchronous operations are supported for this registration. If not
68		 * specified defaults to {@code true}.
69		 * @param asyncSupported if async is supported
70		 */
71		public void setAsyncSupported(boolean asyncSupported) {
72			this.asyncSupported = asyncSupported;
73		}
74	
75		/**
76		 * Returns if asynchronous operations are supported for this registration.
77		 * @return if async is supported
78		 */
79		public boolean isAsyncSupported() {
80			return this.asyncSupported;
81		}
82	
83		/**
84		 * Set init-parameters for this registration. Calling this method will replace any
85		 * existing init-parameters.
86		 * @param initParameters the init parameters
87		 * @see #getInitParameters
88		 * @see #addInitParameter
89		 */
90		public void setInitParameters(Map<String, String> initParameters) {
91			Assert.notNull(initParameters, "'initParameters' must not be null");
92			this.initParameters = new LinkedHashMap<>(initParameters);
93		}
94	
95		/**
96		 * Returns a mutable Map of the registration init-parameters.
97		 * @return the init parameters
98		 */
99		public Map<String, String> getInitParameters() {
100			return this.initParameters;
101		}
102	
103		/**
104		 * Add a single init-parameter, replacing any existing parameter with the same name.
105		 * @param name the init-parameter name
106		 * @param value the init-parameter value
107		 */
108		public void addInitParameter(String name, String value) {
109			Assert.notNull(name, "'name' must not be null");
110			this.initParameters.put(name, value);
111		}
112	
113		@Override
114		protected final void register(String description, ServletContext servletContext) {
115			D registration = addRegistration(description, servletContext);
116			if (registration == null) {
117				if (this.ignoreRegistrationFailure) {
118					logger.info(StringUtils.capitalize(description) + " was not registered (possibly already registered?)");
119					return;
120				}
121				throw new IllegalStateException(
122						"Failed to register '%s' on the servlet context. Possibly already registered?"
123							.formatted(description));
124			}
125			configure(registration);
126		}
127	
128		/**
129		 * Sets whether registration failures should be ignored. If set to true, a failure
130		 * will be logged. If set to false, an {@link IllegalStateException} will be thrown.
131		 * @param ignoreRegistrationFailure whether to ignore registration failures
132		 * @since 3.1.0
133		 */
134		public void setIgnoreRegistrationFailure(boolean ignoreRegistrationFailure) {
135			this.ignoreRegistrationFailure = ignoreRegistrationFailure;
136		}
137	
138		@Override
139		public void setBeanName(String name) {
140			this.beanName = name;
141		}
142	
143		protected abstract @Nullable D addRegistration(String description, ServletContext servletContext);
144	
145		protected void configure(D registration) {
146			registration.setAsyncSupported(this.asyncSupported);
147			if (!this.initParameters.isEmpty()) {
148				registration.setInitParameters(this.initParameters);
149			}
150		}
151	
152		/**
153		 * Deduces the name for this registration. Will return user specified name or fallback
154		 * to the bean name. If the bean name is not available, convention based naming is
155		 * used.
156		 * @param value the object used for convention based names
157		 * @return the deduced name
158		 */
159		protected final String getOrDeduceName(@Nullable Object value) {
160			if (this.name != null) {
161				return this.name;
162			}
163			if (this.beanName != null) {
164				return this.beanName;
165			}
166			if (value == null) {
167				return "null";
168			}
169			return Conventions.getVariableName(value);
170		}
171	
172	}
