30	/**
31	 * A {@link ServletContextInitializer} to register {@link DelegatingFilterProxy}s in a
32	 * Servlet 3.0+ container. Similar to the {@link ServletContext#addFilter(String, Filter)
33	 * registration} features provided by {@link ServletContext} but with a Spring Bean
34	 * friendly design.
35	 * <p>
36	 * The bean name of the actual delegate {@link Filter} should be specified using the
37	 * {@code targetBeanName} constructor argument. Unlike the {@link FilterRegistrationBean},
38	 * referenced filters are not instantiated early. In fact, if the delegate filter bean is
39	 * marked {@code @Lazy} it won't be instantiated at all until the filter is called.
40	 * <p>
41	 * Registrations can be associated with {@link #setUrlPatterns URL patterns} and/or
42	 * servlets (either by {@link #setServletNames name} or through a
43	 * {@link #setServletRegistrationBeans ServletRegistrationBean}s). When no URL pattern or
44	 * servlets are specified the filter will be associated to '/*'. The targetBeanName will
45	 * be used as the filter name if not otherwise specified.
46	 *
47	 * @author Phillip Webb
48	 * @since 1.4.0
49	 * @see ServletContextInitializer
50	 * @see ServletContext#addFilter(String, Filter)
51	 * @see FilterRegistrationBean
52	 * @see DelegatingFilterProxy
53	 */
54	public class DelegatingFilterProxyRegistrationBean extends AbstractFilterRegistrationBean<DelegatingFilterProxy>
55			implements ApplicationContextAware {
56	
57		@SuppressWarnings("NullAway.Init")
58		private ApplicationContext applicationContext;
59	
60		private final String targetBeanName;
61	
62		/**
63		 * Create a new {@link DelegatingFilterProxyRegistrationBean} instance to be
64		 * registered with the specified {@link ServletRegistrationBean}s.
65		 * @param targetBeanName name of the target filter bean to look up in the Spring
66		 * application context (must not be {@code null}).
67		 * @param servletRegistrationBeans associate {@link ServletRegistrationBean}s
68		 */
69		public DelegatingFilterProxyRegistrationBean(String targetBeanName,
70				ServletRegistrationBean<?>... servletRegistrationBeans) {
71			super(servletRegistrationBeans);
72			Assert.hasLength(targetBeanName, "'targetBeanName' must not be empty");
73			this.targetBeanName = targetBeanName;
74			setName(targetBeanName);
75		}
76	
77		@Override
78		public void setApplicationContext(ApplicationContext applicationContext) throws BeansException {
79			this.applicationContext = applicationContext;
80		}
81	
82		protected String getTargetBeanName() {
83			return this.targetBeanName;
84		}
85	
86		@Override
87		public DelegatingFilterProxy getFilter() {
88			return new DelegatingFilterProxy(this.targetBeanName, getWebApplicationContext()) {
89	
90				@Override
91				protected void initFilterBean() throws ServletException {
92					// Don't initialize filter bean on init()
93				}
94	
95			};
96		}
97	
98		private WebApplicationContext getWebApplicationContext() {
99			Assert.state(this.applicationContext != null, "ApplicationContext has not been injected");
100			Assert.state(this.applicationContext instanceof WebApplicationContext,
101					"Injected ApplicationContext is not a WebApplicationContext");
102			return (WebApplicationContext) this.applicationContext;
103		}
104	
105	}
